 16→syntax = "proto3";
 17→
 18→package controlplane.v1;
 19→
 20→import "buf/validate/validate.proto";
 21→import "google/api/annotations.proto";
 22→import "google/protobuf/timestamp.proto";
 23→import "protoc-gen-openapiv2/options/annotations.proto";
 24→
 25→option go_package = "github.com/chainloop-dev/chainloop/app/controlplane/api/controlplane/v1;v1";
 26→
 27→service ReferrerService {
 28→  // DiscoverPrivate returns the referrer item for a given digest in the organizations of the logged-in user
 29→  rpc DiscoverPrivate(ReferrerServiceDiscoverPrivateRequest) returns (ReferrerServiceDiscoverPrivateResponse) {
 30→    option (google.api.http) = {get: "/discover/{digest}"};
 31→    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
 32→      summary: "Discover private referrer"
 33→      description: "Returns the referrer item for a given digest in the organizations of the logged-in user"
 34→      produces: ["application/json"]
 35→    };
 36→  }
 37→  // DiscoverPublicShared returns the referrer item for a given digest in the public shared index
 38→  rpc DiscoverPublicShared(DiscoverPublicSharedRequest) returns (DiscoverPublicSharedResponse) {
 39→    option (google.api.http) = {get: "/discover/shared/{digest}"};
 40→    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
 41→      summary: "Discover public shared referrer"
 42→      description: "Returns the referrer item for a given digest in the public shared index"
 43→      produces: ["application/json"]
 44→    };
 45→  }
 46→
 47→  option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_tag) = {
 48→    name: "ReferrerService"
 49→    description: "Referrer service for discovering referred content by digest"
 50→  };
 51→}
 52→
 53→// ReferrerServiceDiscoverPrivateRequest is the request for the DiscoverPrivate method
 54→message ReferrerServiceDiscoverPrivateRequest {
 55→  // Digest is the unique identifier of the referrer to discover
 56→  string digest = 1 [(buf.validate.field).string = {min_len: 1}];
 57→  // Kind is the optional type of referrer, i.e CONTAINER_IMAGE, GIT_HEAD, ...
 58→  // Used to filter and resolve ambiguities
 59→  string kind = 2;
 60→
 61→  option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_schema) = {
 62→    json_schema: {
 63→      title: "ReferrerServiceDiscoverPrivateRequest"
 64→      description: "Request to discover a private referrer"
 65→    }
 66→  };
 67→}
 68→
 69→// DiscoverPublicSharedRequest is the request for the DiscoverPublicShared method
 70→message DiscoverPublicSharedRequest {
 71→  // Digest is the unique identifier of the referrer to discover
 72→  string digest = 1 [(buf.validate.field).string = {min_len: 1}];
 73→  // Kind is the optional type of referrer, i.e CONTAINER_IMAGE, GIT_HEAD, ...
 74→  // Used to filter and resolve ambiguities
 75→  string kind = 2;
 76→
 77→  option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_schema) = {
 78→    json_schema: {
 79→      title: "DiscoverPublicSharedRequest"
 80→      description: "Request to discover a public shared referrer"
 81→    }
 82→  };
 83→}
 84→
 85→// DiscoverPublicSharedResponse is the response for the DiscoverPublicShared method
 86→message DiscoverPublicSharedResponse {
 87→  // Result is the discovered referrer item
 88→  ReferrerItem result = 1;
 89→
 90→  option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_schema) = {
 91→    json_schema: {
 92→      title: "DiscoverPublicSharedResponse"
 93→      description: "Response for the DiscoverPublicShared method"
 94→    }
 95→  };
 96→}
 97→
 98→// ReferrerServiceDiscoverPrivateResponse is the response for the DiscoverPrivate method
 99→message ReferrerServiceDiscoverPrivateResponse {
100→  // Result is the discovered referrer item
101→  ReferrerItem result = 1;
102→
103→  option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_schema) = {
104→    json_schema: {
105→      title: "ReferrerServiceDiscoverPrivateResponse"
106→      description: "Response for the DiscoverPrivate method"
107→    }
108→  };
109→}
110→
111→// ReferrerItem represents a referrer object in the system
112→message ReferrerItem {
113→  // Digest of the referrer, i.e sha256:deadbeef or sha1:beefdead
114→  string digest = 1;
115→  // Kind of referrer, i.e CONTAINER_IMAGE, GIT_HEAD, ...
116→  string kind = 2;
117→  // Downloadable indicates whether the referrer is downloadable or not from CAS
118→  bool downloadable = 3;
119→  // Public indicates whether the referrer is public since it belongs to a public workflow
120→  bool public = 6;
121→  // References contains the list of related referrer items
122→  repeated ReferrerItem references = 4;
123→  // CreatedAt is the timestamp when the referrer was created
124→  google.protobuf.Timestamp created_at = 5;
125→  // Metadata contains additional descriptive information about the referrer
126→  map<string, string> metadata = 7;
127→  // Annotations are key-value pairs associated with the referrer
128→  map<string, string> annotations = 8;
129→
130→  option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_schema) = {
131→    json_schema: {
132→      title: "ReferrerItem"
133→      description: "It represents a referrer object in the system"
134→    }
135→  };
136→}
