 34→type ReferrerRepo struct {
 35→	data         *Data
 36→	log          *log.Helper
 37→	workflowRepo biz.WorkflowRepo
 38→}
 39→
 40→func NewReferrerRepo(data *Data, wfRepo biz.WorkflowRepo, logger log.Logger) biz.ReferrerRepo {
 41→	return &ReferrerRepo{
 42→		data:         data,
 43→		log:          log.NewHelper(logger),
 44→		workflowRepo: wfRepo,
 45→	}
 46→}
 47→
 48→type storedReferrerMap map[string]uuid.UUID
 49→
 50→func (r *ReferrerRepo) Save(ctx context.Context, referrers []*biz.Referrer, workflowID uuid.UUID) (err error) {
 51→	// find the workflow
 52→	wf, err := r.workflowRepo.FindByID(ctx, workflowID)
 53→	if err != nil {
 54→		return fmt.Errorf("failed to find workflow: %w", err)
 55→	} else if wf == nil {
 56→		return biz.NewErrNotFound("workflow")
 57→	}
 58→
 59→	storedMap := make(storedReferrerMap)
 60→
 61→	for _, ref := range referrers {
 62→		// Check if it exists already, if not create it
 63→		storedID, err := r.data.DB.Referrer.Create().
 64→			SetDigest(ref.Digest).SetKind(ref.Kind).SetDownloadable(ref.Downloadable).
 65→			SetMetadata(ref.Metadata).SetAnnotations(ref.Annotations).
 66→			AddWorkflowIDs(workflowID).
 67→			OnConflictColumns(
 68→				referrer.FieldDigest, referrer.FieldKind,
 69→			).UpdateNewValues().ID(ctx)
 70→		if err != nil {
 71→			return fmt.Errorf("failed to create referrer: %w", err)
 72→		}
 73→
 74→		storedRef, err := r.data.DB.Referrer.Query().Select(referrer.FieldID).Where(referrer.ID(storedID)).First(ctx)
 75→		if err != nil {
 76→			return fmt.Errorf("failed to load referrer: %w", err)
 77→		} else if storedRef == nil {
 78→			return fmt.Errorf("failed to load referrer: %w", err)
 79→		}
 80→
 81→		// Store it in the map
 82→		storedMap[ref.MapID()] = storedRef.ID
 83→	}
 84→
 85→	// 2 - define the relationship between referrers
 86→	for _, parentRef := range referrers {
 87→		// This is the current item stored in DB
 88→		storedReferrer := storedMap[parentRef.MapID()]
 89→		// Iterate on the items it refer to (references)
 90→		var references []uuid.UUID
 91→		for _, ref := range parentRef.References {
 92→			// amd find it in the DB
 93→			storedReference, ok := storedMap[ref.MapID()]
 94→			if !ok {
 95→				return fmt.Errorf("referrer %v not found", ref)
 96→			}
 97→
 98→			references = append(references, storedReference)
 99→		}
100→
101→		if len(references) == 0 {
102→			continue
103→		}
104→
105→		// Create the relationship
106→		if err := r.data.DB.Referrer.UpdateOneID(storedReferrer).AddReferenceIDs(references...).Exec(ctx); err != nil {
107→			return fmt.Errorf("failed to create referrer relationship: %w", err)
108→		}
109→	}
110→
111→	return nil
112→}
113→
114→// Check if a given referrer by digest exist. The query can be scoped further down if needed by providing the kind or visibility status
115→func (r *ReferrerRepo) Exist(ctx context.Context, digest string, filters ...biz.GetFromRootFilter) (bool, error) {
116→	opts := &biz.GetFromRootFilters{}
117→	for _, f := range filters {
118→		f(opts)
119→	}
120→
121→	query := r.data.DB.Referrer.Query().Where(referrer.DigestEQ(digest))
122→	// We might be filtering by the rootKind, this will prevent ambiguity
123→	if opts.RootKind != nil {
124→		query = query.Where(referrer.Kind(*opts.RootKind))
125→	}
126→
127→	if opts.Public != nil {
128→		query = query.WithWorkflows(func(q *ent.WorkflowQuery) { q.Where(workflow.PublicEQ(*opts.Public)) })
129→	}
130→
131→	return query.Exist(ctx)
132→}
133→
134→func (r *ReferrerRepo) GetFromRoot(ctx context.Context, digest string, orgIDs []uuid.UUID, filters ...biz.GetFromRootFilter) (*biz.StoredReferrer, error) {
135→	opts := &biz.GetFromRootFilters{}
136→	for _, f := range filters {
137→		f(opts)
138→	}
139→
140→	// Find the referrer from its digest + artifactType (optional)
141→	// if there is more than 1 item we return ReferrerAmbiguous error
142→	// filter by the allowed organizations and by the visibility of the attached workflows if needed
143→	predicateReferrer := []predicate.Referrer{
144→		referrer.Digest(digest),
145→	}
146→
147→	// We might be filtering by the rootKind, this will prevent ambiguity
148→	if opts.RootKind != nil {
149→		predicateReferrer = append(predicateReferrer, referrer.Kind(*opts.RootKind))
150→	}
151→
152→	// Prepare the workflow query predicate
153→	predicateWF := []predicate.Workflow{
154→		workflow.DeletedAtIsNil(), workflow.HasOrganizationWith(organization.IDIn(orgIDs...)),
155→	}
156→
157→	// optionally attaching its visibility
158→	if opts.Public != nil {
159→		predicateWF = append(predicateWF, workflow.Public(*opts.Public))
160→	}
161→
162→	// Attach the workflow predicate
163→	predicateReferrer = append(predicateReferrer, referrer.HasWorkflowsWith(predicateWF...))
164→
165→	refs, err := r.data.DB.Referrer.Query().Where(predicateReferrer...).WithWorkflows().All(ctx)
166→	if err != nil {
167→		return nil, fmt.Errorf("failed to query referrer: %w", err)
168→	}
169→
170→	// No items found
171→	if numrefs := len(refs); numrefs == 0 {
172→		return nil, nil
173→	} else if numrefs > 1 {
174→		// if there is more than 1 item with the same digest+artifactType we will fail
175→		var kinds []string
176→		for _, r := range refs {
177→			kinds = append(kinds, r.Kind)
178→		}
179→		return nil, biz.NewErrReferrerAmbiguous(digest, kinds)
180→	}
181→
182→	// Find the referrer recursively starting from the root
183→	res, err := r.doGet(ctx, refs[0], orgIDs, opts.ProjectIDs, opts.Public, 0)
184→	if err != nil && !biz.IsErrUnauthorized(err) {
185→		return nil, fmt.Errorf("failed to get referrer: %w", err)
186→	}
187→
188→	return res, nil
189→}
190→
191→// max number of recursive levels to traverse
192→// we just care about 1 level, i.e att -> commit, or commit -> attestation
193→// we also need to limit this because there might be cycles
194→const maxTraverseLevels = 1
195→
196→func (r *ReferrerRepo) doGet(ctx context.Context, root *ent.Referrer, allowedOrgs []uuid.UUID, visibleProjectsMap map[uuid.UUID][]uuid.UUID, public *bool, level int) (*biz.StoredReferrer, error) {
197→	// Assemble the referrer to return
198→	res := &biz.StoredReferrer{
199→		ID:        root.ID,
200→		CreatedAt: toTimePtr(root.CreatedAt),
201→		Referrer: &biz.Referrer{
202→			Digest:       root.Digest,
203→			Kind:         root.Kind,
204→			Downloadable: root.Downloadable,
205→			Metadata:     root.Metadata,
206→			Annotations:  root.Annotations,
207→		},
208→	}
209→
210→	// add additional information related to the workflows
211→	hydrateWorkflowsInfo(root, res)
212→
213→	// check that, if RBAC is required, the user has visibility on the artifact in at least 1 org/project
214→	if visible := isReferrerVisible(res, allowedOrgs, visibleProjectsMap); !visible {
215→		return nil, biz.NewErrUnauthorizedStr("referrer not allowed")
216→	}
217→
218→	// Next: We'll find the references recursively up to a max of maxTraverseLevels levels
219→	if level >= maxTraverseLevels {
220→		return res, nil
221→	}
222→
223→	// Find the references and call recursively filtered out by the allowed organizations
224→	// and by the visibility if needed
225→	predicateReferrer := []predicate.Referrer{}
226→
227→	predicateWF := []predicate.Workflow{
228→		workflow.DeletedAtIsNil(), workflow.HasOrganizationWith(organization.IDIn(allowedOrgs...)),
229→	}
230→
231→	// optionally attaching its visibility
232→	if public != nil {
233→		predicateWF = append(predicateWF, workflow.Public(*public))
234→	}
235→
236→	// Attach the workflow predicate
237→	predicateReferrer = append(predicateReferrer, referrer.HasWorkflowsWith(predicateWF...))
238→
239→	// sort the references by creation date in descending order
240→	// so whenever we add pagination we'll get the latest x references
241→	refs, err := root.QueryReferences().Where(predicateReferrer...).WithWorkflows().Order(referrer.ByCreatedAt(), ent.Desc()).All(ctx)
242→	if err != nil {
243→		return nil, fmt.Errorf("failed to query references: %w", err)
244→	}
245→
246→	// Add the references to the result
247→	for _, reference := range refs {
248→		// Call recursively the function
249→		// we return all the references
250→		ref, err := r.doGet(ctx, reference, allowedOrgs, visibleProjectsMap, public, level+1)
251→		if err != nil && !biz.IsErrUnauthorized(err) {
252→			return nil, fmt.Errorf("failed to get referrer: %w", err)
253→		}
254→
255→		if ref != nil {
256→			res.References = append(res.References, ref)
257→		}
258→	}
259→
260→	return res, nil
261→}
262→
263→func isReferrerVisible(ref *biz.StoredReferrer, allowedOrgs []uuid.UUID, visibleProjectsMap map[uuid.UUID][]uuid.UUID) bool {
264→	if ref.InPublicWorkflow {
265→		return true
266→	}
267→
268→	for _, oid := range ref.OrgIDs {
269→		if !slices.Contains(allowedOrgs, oid) {
270→			// skip check in organizations where the user doesn't have access
271→			continue
272→		}
273→		if visibleProjects, ok := visibleProjectsMap[oid]; ok {
274→			// if entry is present, it means we need to apply RBAC
275→			// check if visible projects and referrer projects match
276→			// by checking if any project is visible by the user
277→			for _, pid := range ref.ProjectIDs {
278→				if slices.Contains(visibleProjects, pid) {
279→					return true
280→				}
281→			}
282→		} else {
283→			// if entry is not found in the map, it means that RBAC is not needed for this org, we have finished
284→			return true
285→		}
286→	}
287→
288→	return false
289→}
290→
291→// hydrate the referrer with the following information:
292→// - isPublic: if it has a public workflow associated
293→// - workflowIDs: the list of associated workflows
294→// - orgIDs: the list of associated organizations
295→func hydrateWorkflowsInfo(root *ent.Referrer, out *biz.StoredReferrer) {
296→	isPublic := false
297→	workflowIDs := make([]uuid.UUID, 0, len(root.Edges.Workflows))
298→	projectIDs := make(map[uuid.UUID]bool, 0)
299→	orgIDs := make([]uuid.UUID, 0)
300→	orgsMap := make(map[uuid.UUID]struct{}, 0)
301→	for _, wf := range root.Edges.Workflows {
302→		if wf.Public {
303→			isPublic = true
304→		}
305→		workflowIDs = append(workflowIDs, wf.ID)
306→		if _, ok := orgsMap[wf.OrganizationID]; !ok {
307→			orgIDs = append(orgIDs, wf.OrganizationID)
308→		}
309→		if _, ok := projectIDs[wf.ProjectID]; !ok {
310→			projectIDs[wf.ProjectID] = true
311→		}
312→		orgsMap[wf.OrganizationID] = struct{}{}
313→	}
314→
315→	out.ProjectIDs = maps.Keys(projectIDs)
316→	out.InPublicWorkflow = isPublic
317→	out.WorkflowIDs = workflowIDs
318→	out.OrgIDs = orgIDs
319→}
