 37→type ReferrerUseCase struct {
 38→	repo              ReferrerRepo
 39→	membershipUseCase *MembershipUseCase
 40→	workflowRepo      WorkflowRepo
 41→	logger            *log.Helper
 42→	indexConfig       *ReferrerSharedIndexConfig
 43→}
 44→
 45→type ReferrerSharedIndexConfig struct {
 46→	Enabled     bool
 47→	AllowedOrgs []string
 48→}
 49→
 50→func NewIndexConfig(cfg *conf.ReferrerSharedIndex) (*ReferrerSharedIndexConfig, error) {
 51→	// referrer shared index is optional, if not configured, it's disabled
 52→	if cfg == nil {
 53→		return nil, nil
 54→	}
 55→
 56→	if err := cfg.ValidateOrgs(); err != nil {
 57→		return nil, fmt.Errorf("invalid shared index config: %w", err)
 58→	}
 59→
 60→	return &ReferrerSharedIndexConfig{
 61→		Enabled:     cfg.Enabled,
 62→		AllowedOrgs: cfg.AllowedOrgs,
 63→	}, nil
 64→}
 65→
 66→func NewReferrerUseCase(repo ReferrerRepo, wfRepo WorkflowRepo, membershipUseCase *MembershipUseCase, indexCfg *ReferrerSharedIndexConfig, l log.Logger) (*ReferrerUseCase, error) {
 67→	if l == nil {
 68→		l = log.NewStdLogger(io.Discard)
 69→	}
 70→	logger := servicelogger.ScopedHelper(l, "biz/referrer")
 71→
 72→	if indexCfg != nil && indexCfg.Enabled {
 73→		logger.Infow("msg", "shared index enabled", "allowedOrgs", indexCfg.AllowedOrgs)
 74→	}
 75→
 76→	return &ReferrerUseCase{
 77→		repo:              repo,
 78→		membershipUseCase: membershipUseCase,
 79→		indexConfig:       indexCfg,
 80→		workflowRepo:      wfRepo,
 81→		logger:            logger,
 82→	}, nil
 83→}
 84→
 85→type ReferrerRepo interface {
 86→	Save(ctx context.Context, input []*Referrer, workflowID uuid.UUID) error
 87→	// GetFromRoot returns the referrer identified by the provided content digest, including its first-level references
 88→	// For example if sha:deadbeef represents an attestation, the result will contain the attestation + materials associated to it
 89→	// OrgIDs represent an allowList of organizations where the referrers should be looked for
 90→	GetFromRoot(ctx context.Context, digest string, orgIDs []uuid.UUID, filters ...GetFromRootFilter) (*StoredReferrer, error)
 91→	// Exist Checks if a given referrer by digest exist.
 92→	// The query can be scoped further down if needed by providing the kind or visibility status
 93→	Exist(ctx context.Context, digest string, filters ...GetFromRootFilter) (bool, error)
 94→}
 95→
 96→type Referrer struct {
 97→	Digest string
 98→	Kind   string
 99→	// Wether the item is downloadable from CAS or not
100→	Downloadable bool
101→	// If this referrer is part of a public workflow
102→	InPublicWorkflow bool
103→	References       []*Referrer
104→
105→	Metadata, Annotations map[string]string
106→}
107→
108→// Actual referrer stored in the DB which includes a nested list of storedReferences
109→type StoredReferrer struct {
110→	*Referrer
111→	ID        uuid.UUID
112→	CreatedAt *time.Time
113→	// Fully expanded list of 1-level off references
114→	References                      []*StoredReferrer
115→	OrgIDs, WorkflowIDs, ProjectIDs []uuid.UUID
116→}
117→
118→type OrgID = uuid.UUID
119→type ProjectID = uuid.UUID
120→
121→type GetFromRootFilters struct {
122→	// RootKind is the kind of the root referrer, i.e ATTESTATION
