179→// GetFromRootUser returns the referrer identified by the provided content digest, including its first-level references
180→// For example if sha:deadbeef represents an attestation, the result will contain the attestation + materials associated to it
181→// It only returns referrers that belong to organizations the user is member of
182→func (s *ReferrerUseCase) GetFromRootUser(ctx context.Context, digest, rootKind, userID string) (*StoredReferrer, error) {
183→	userUUID, err := uuid.Parse(userID)
184→	if err != nil {
185→		return nil, NewErrInvalidUUID(err)
186→	}
187→
188→	userOrgs, projectIDs, err := s.membershipUseCase.GetOrgsAndRBACInfoForUser(ctx, userUUID)
189→	if err != nil {
190→		return nil, err
191→	}
192→
193→	// We pass the list of organizationsIDs from where to look for the referrer
194→	// For now we just pass the list of organizations the user is member of
195→	// in the future we will expand this to publicly available orgs and so on.
196→	return s.GetFromRoot(ctx, digest, rootKind, userOrgs, projectIDs)
197→}
198→
199→func (s *ReferrerUseCase) GetFromRoot(ctx context.Context, digest, rootKind string, orgIDs []uuid.UUID, projectIDs map[OrgID][]ProjectID) (*StoredReferrer, error) {
200→	filters := make([]GetFromRootFilter, 0)
201→	if rootKind != "" {
202→		filters = append(filters, WithKind(rootKind))
203→	}
204→	if projectIDs != nil {
205→		filters = append(filters, WithVisibleProjectIDs(projectIDs))
206→	}
207→
208→	ref, err := s.repo.GetFromRoot(ctx, digest, orgIDs, filters...)
209→	if err != nil {
210→		if errors.As(err, &ErrAmbiguousReferrer{}) {
211→			return nil, NewErrValidation(fmt.Errorf("please provide the referrer kind: %w", err))
212→		}
213→
214→		return nil, fmt.Errorf("getting referrer from root: %w", err)
215→	} else if ref == nil {
216→		return nil, NewErrNotFound(fmt.Sprintf("artifact or piece of evidence with digest %s", digest))
217→	}
218→
219→	return ref, nil
220→}
