222→// Get the list of public referrers from organizations
223→// that have been allowed to be shown in a shared index
224→// NOTE: This is a public endpoint under /discover/[sha256:deadbeef]
225→func (s *ReferrerUseCase) GetFromRootInPublicSharedIndex(ctx context.Context, digest, rootKind string) (*StoredReferrer, error) {
226→	if s.indexConfig == nil || !s.indexConfig.Enabled {
227→		return nil, NewErrUnauthorizedStr("shared referrer index functionality is not enabled")
228→	}
229→
230→	// Load the organizations that are allowed to appear in the shared index
231→	orgIDs := make([]uuid.UUID, 0)
232→	for _, orgID := range s.indexConfig.AllowedOrgs {
233→		orgUUID, err := uuid.Parse(orgID)
234→		if err != nil {
235→			return nil, NewErrInvalidUUID(err)
236→		}
237→		orgIDs = append(orgIDs, orgUUID)
238→	}
239→
240→	// and ask only for the public referrers of those orgs
241→	filters := []GetFromRootFilter{WithPublicVisibility(true)}
242→	if rootKind != "" {
243→		filters = append(filters, WithKind(rootKind))
244→	}
245→
246→	ref, err := s.repo.GetFromRoot(ctx, digest, orgIDs, filters...)
247→	if err != nil {
248→		if errors.As(err, &ErrAmbiguousReferrer{}) {
249→			return nil, NewErrValidation(fmt.Errorf("please provide the referrer kind: %w", err))
250→		}
251→
252→		return nil, fmt.Errorf("getting referrer from root: %w", err)
253→	} else if ref == nil {
254→		return nil, NewErrNotFound(fmt.Sprintf("artifact or piece of evidence with digest %s", digest))
255→	}
256→
257→	return ref, nil
258→}
