260→const (
261→	referrerAttestationType = "ATTESTATION"
262→	referrerGitHeadType     = "GIT_HEAD_COMMIT"
263→)
264→
265→func newRef(digest, kind string) string {
266→	return fmt.Sprintf("%s-%s", kind, digest)
267→}
268→
269→func (r *Referrer) MapID() string {
270→	return newRef(r.Digest, r.Kind)
271→}
272→
273→// ExtractReferrers extracts the referrers from the given attestation
274→// this means
275→// 1 - write an entry for the attestation itself
276→// 2 - then to all the materials contained in the predicate
277→// 3 - and the subjects (some of them)
278→// 4 - creating link between the attestation and the materials/subjects as needed
279→// see tests for examples
280→func extractReferrers(att *dsse.Envelope, digest cr_v1.Hash, repo ReferrerRepo) ([]*Referrer, error) {
281→	referrersMap := make(map[string]*Referrer)
282→	// 1 - Attestation referrer
283→	// Add the attestation itself as a referrer to the map without references yet
284→	attestationHash := digest.String()
285→	attestationReferrer := &Referrer{
286→		Digest:       attestationHash,
287→		Kind:         referrerAttestationType,
288→		Downloadable: true,
289→	}
290→
291→	referrersMap[newRef(attestationHash, referrerAttestationType)] = attestationReferrer
292→
293→	// 2 - Predicate that's referenced from the attestation
294→	predicate, err := chainloop.ExtractPredicate(att)
295→	if err != nil {
296→		return nil, fmt.Errorf("extracting predicate: %w", err)
297→	}
298→
299→	// We currently only support adding additional information about the attestation kind
300→	// We add both annotations and workflow metadata
301→	attestationReferrer.Annotations = predicate.GetAnnotations()
302→	hasViolations := predicate.GetPolicyEvaluationStatus().HasViolations
303→	hasGatedViolations := predicate.GetPolicyEvaluationStatus().HasGatedViolations
304→	attestationReferrer.Metadata = map[string]string{
305→		// workflow name, team and project
306→		"name":                     predicate.GetMetadata().Name,
307→		"team":                     predicate.GetMetadata().Team,
308→		"project":                  predicate.GetMetadata().Project,
309→		"hasPolicyViolations":      fmt.Sprintf("%t", hasViolations),
310→		"hasGatedPolicyViolations": fmt.Sprintf("%t", hasGatedViolations),
311→		"projectVersion":           predicate.GetMetadata().ProjectVersion,
312→		"projectVersionPrerelease": fmt.Sprintf("%t", predicate.GetMetadata().ProjectVersionPrerelease),
313→		"organization":             predicate.GetMetadata().Organization,
314→		"contractName":             predicate.GetMetadata().ContractName,
315→		"contractVersion":          predicate.GetMetadata().ContractVersion,
316→	}
317→
318→	// Create new referrers for each material
319→	// and link them to the attestation
320→	for _, material := range predicate.GetMaterials() {
321→		// Skip materials that don't have a digest
322→		if material.Hash == nil {
323→			continue
324→		}
325→
326→		// If we are inserting an attestation as a dependent, we want to make sure it already exists
327→		// stored in the system. This is so we can ensure that the attestations nodes are created through
328→		// an attestation process, not as a referenced provided by the user
329→		if material.Type == referrerAttestationType {
330→			if exists, err := repo.Exist(context.Background(), material.Hash.String(), WithKind(referrerAttestationType)); err != nil {
331→				return nil, fmt.Errorf("checking if attestation exists: %w", err)
332→			} else if !exists {
333→				return nil, fmt.Errorf("attestation material does not exist %q", material.Hash.String())
334→			}
335→		}
336→
337→		// Create its referrer entry if it doesn't exist yet
338→		// the reason it might exist is because you might be attaching the same material twice
339→		// i.e the same SBOM twice, in that case we don't want to create a new referrer
340→		materialRef := newRef(material.Hash.String(), material.Type)
341→		if _, ok := referrersMap[materialRef]; ok {
342→			continue
343→		}
344→
345→		referrersMap[materialRef] = &Referrer{
346→			Digest:       material.Hash.String(),
347→			Kind:         material.Type,
348→			Downloadable: material.UploadedToCAS,
349→		}
350→
351→		materialReferrer := referrersMap[materialRef]
352→
353→		// We create a bidirectional link between the attestation and the material
354→		// material -> attestation (1-1)
355→		materialReferrer.References = []*Referrer{{Digest: attestationReferrer.Digest, Kind: attestationReferrer.Kind}}
356→		// attestation -> material (1-N)
357→		attestationReferrer.References = append(attestationReferrer.References, &Referrer{
358→			Digest: materialReferrer.Digest, Kind: materialReferrer.Kind,
359→		})
360→	}
361→
362→	// 3 - Subject that points to the attestation
363→	statement, err := chainloop.ExtractStatement(att)
364→	if err != nil {
365→		return nil, fmt.Errorf("extracting predicate: %w", err)
366→	}
367→
368→	// Materials can also be subjects, but there are cases that we will have a subject that is not a material
369→	// For example, a git head commit, that's why we need to also add the subjects as referrers (if needed)
370→	for _, subject := range statement.Subject {
371→		subjectReferrer, err := intotoSubjectToReferrer(subject)
372→		if err != nil {
373→			return nil, fmt.Errorf("transforming subject to referrer: %w", err)
374→		}
375→
376→		if subjectReferrer == nil {
377→			continue
378→		}
379→
380→		subjectRef := newRef(subjectReferrer.Digest, subjectReferrer.Kind)
381→
382→		// check if we already have a referrer for this digest and skip if it's the case
383→		if _, ok := referrersMap[subjectRef]; ok {
384→			continue
385→		}
386→
387→		// We are now in the case where a subject is not a material, i.e a git head commit, we need to add it to the referrers
388→		// with a bidirectional link to the attestation like we did for the materials
389→		referrersMap[subjectRef] = subjectReferrer
390→		// add it to the list of of attestation-referenced digests
391→		attestationReferrer.References = append(attestationReferrer.References,
392→			&Referrer{
393→				Digest: subjectReferrer.Digest, Kind: subjectReferrer.Kind,
394→			})
395→
396→		// Update referrer to point to the attestation
397→		referrersMap[subjectRef].References = []*Referrer{{Digest: attestationReferrer.Digest, Kind: attestationReferrer.Kind}}
398→	}
399→
400→	// Return a sorted list of referrers
401→	mapKeys := make([]string, 0, len(referrersMap))
402→	for k := range referrersMap {
403→		mapKeys = append(mapKeys, k)
404→	}
405→	sort.Strings(mapKeys)
406→
407→	referrers := make([]*Referrer, 0, len(referrersMap))
408→	for _, k := range mapKeys {
409→		referrers = append(referrers, referrersMap[k])
410→	}
411→
412→	return referrers, nil
413→}
414→
415→// transforms the in-toto subject to a referrer by deterministically picking
416→// the subject types we care about (and return nil otherwise), for now we just care about the subjects
417→// - git.Head and
418→// - material types
419→func intotoSubjectToReferrer(r *v1.ResourceDescriptor) (*Referrer, error) {
420→	var digestStr string
421→	for alg, val := range r.Digest {
422→		digestStr = fmt.Sprintf("%s:%s", alg, val)
423→		break
424→	}
425→
426→	// it's a.git head type
427→	if r.Name == chainloop.SubjectGitHead {
428→		if digestStr == "" {
429→			return nil, fmt.Errorf("no digest found for subject %s", r.Name)
430→		}
431→
432→		return &Referrer{
433→			Digest: digestStr,
434→			Kind:   referrerGitHeadType,
435→		}, nil
436→	}
437→
438→	// Iterate on material types
439→	var materialType string
440→	var uploadedToCAS bool
441→	// it's a material type
442→	for k, v := range r.Annotations.AsMap() {
443→		// It's a material type
444→		if k == v2.AnnotationMaterialType {
445→			materialType = v.(string)
446→		} else if k == v2.AnnotationMaterialCAS {
447→			uploadedToCAS = v.(bool)
448→		}
449→	}
450→
451→	// it's not a material type
452→	if materialType == "" {
453→		return nil, nil
454→	}
455→
456→	if digestStr == "" {
457→		return nil, fmt.Errorf("no digest found for subject %s", r.Name)
458→	}
459→
460→	return &Referrer{
461→		Digest:       digestStr,
462→		Kind:         materialType,
463→		Downloadable: uploadedToCAS,
464→	}, nil
465→}
