 42→func (s *ReferrerService) DiscoverPrivate(ctx context.Context, req *pb.ReferrerServiceDiscoverPrivateRequest) (*pb.ReferrerServiceDiscoverPrivateResponse, error) {
 43→	currentUser, currentToken, err := requireCurrentUserOrAPIToken(ctx)
 44→	if err != nil {
 45→		return nil, err
 46→	}
 47→
 48→	currentOrg, err := requireCurrentOrg(ctx)
 49→	if err != nil {
 50→		return nil, err
 51→	}
 52→
 53→	// if we are logged in as user we find the referrer from the user
 54→	// otherwise for the current organization associated with the API token
 55→	var referrer *biz.StoredReferrer
 56→	if currentUser != nil {
 57→		referrer, err = s.referrerUC.GetFromRootUser(ctx, req.GetDigest(), req.GetKind(), currentUser.ID)
 58→	} else if currentToken != nil {
 59→		var orgUUID uuid.UUID
 60→		orgUUID, err = uuid.Parse(currentOrg.ID)
 61→		if err != nil {
 62→			return nil, fmt.Errorf("invalid org UUID: %w", err)
 63→		}
 64→
 65→		// Apply RBAC visibility for api tokens (only for the current organization)
 66→		orgsProjectsMap := make(map[uuid.UUID][]uuid.UUID)
 67→		visibleProjects := s.visibleProjects(ctx)
 68→		if visibleProjects != nil {
 69→			orgsProjectsMap[orgUUID] = visibleProjects
 70→		}
 71→
 72→		referrer, err = s.referrerUC.GetFromRoot(ctx, req.GetDigest(), req.GetKind(), []uuid.UUID{orgUUID}, orgsProjectsMap)
 73→	}
 74→	if err != nil {
 75→		return nil, handleUseCaseErr(err, s.log)
 76→	}
 77→
 78→	return &pb.ReferrerServiceDiscoverPrivateResponse{
 79→		Result: bizReferrerToPb(referrer),
 80→	}, nil
 81→}
