 94→func bizReferrerToPb(r *biz.StoredReferrer) *pb.ReferrerItem {
 95→	item := &pb.ReferrerItem{
 96→		Digest:       r.Digest,
 97→		Downloadable: r.Downloadable,
 98→		Public:       r.InPublicWorkflow,
 99→		Kind:         r.Kind,
100→		CreatedAt:    timestamppb.New(*r.CreatedAt),
101→		Metadata:     r.Metadata,
102→		Annotations:  r.Annotations,
103→	}
104→
105→	for _, r := range r.References {
106→		item.References = append(item.References, bizReferrerToPb(r))
107→	}
108→
109→	return item
110→}
