214→// Create will add a new WorkflowRun, associate it to a schemaVersion and increment the counter in the associated workflow
215→func (uc *WorkflowRunUseCase) Create(ctx context.Context, opts *WorkflowRunCreateOpts) (*WorkflowRun, error) {
216→	workflowUUID, err := uuid.Parse(opts.WorkflowID)
217→	if err != nil {
218→		return nil, err
219→	}
220→
221→	if opts.CASBackendID == uuid.Nil {
222→		return nil, errors.New("CASBackendID cannot be nil")
223→	}
224→
225→	if opts.ContractRevision == nil {
226→		return nil, errors.New("contract revision cannot be nil")
227→	}
228→
229→	contractRevision := opts.ContractRevision
230→
231→	if opts.ProjectVersion != "" {
232→		if err := ValidateVersion(opts.ProjectVersion); err != nil {
233→			return nil, err
234→		}
235→	}
236→
237→	// For now we only associate the workflow run to one backend.
238→	// This might change in the future so we prepare the data layer to support an array of associated backends
239→	backends := []uuid.UUID{opts.CASBackendID}
240→	result, err := uc.wfRunRepo.Create(ctx,
241→		&WorkflowRunRepoCreateOpts{
242→			WorkflowID:             workflowUUID,
243→			SchemaVersionID:        contractRevision.Version.ID,
244→			RunURL:                 opts.RunnerRunURL,
245→			RunnerType:             opts.RunnerType,
246→			Backends:               backends,
247→			LatestRevision:         contractRevision.Contract.LatestRevision,
248→			UsedRevision:           contractRevision.Version.Revision,
249→			ProjectVersion:         opts.ProjectVersion,
250→			RequireExistingVersion: opts.RequireExistingVersion,
251→		})
252→	if err != nil {
253→		return nil, err
254→	}
255→
256→	// Dispatch audit event for project version creation if a new version was created
257→	if result.VersionCreated && uc.auditorUC != nil && result.Project != nil {
258→		uc.auditorUC.Dispatch(ctx, &events.ProjectVersionCreated{
259→			ProjectBase: &events.ProjectBase{
260→				ProjectID:   &result.Project.ID,
261→				ProjectName: result.Project.Name,
262→			},
263→			VersionID:  &result.Run.ProjectVersion.ID,
264→			Version:    result.Run.ProjectVersion.Version,
265→			Prerelease: result.Run.ProjectVersion.Prerelease,
266→		}, &result.Project.OrgID)
267→	}
268→
269→	return result.Run, nil
270→}
