296→func (uc *WorkflowRunUseCase) SaveAttestation(ctx context.Context, id string, envelope, bundle []byte) (*v1.Hash, error) {
297→	runID, err := uuid.Parse(id)
298→	if err != nil {
299→		return nil, NewErrInvalidUUID(err)
300→	}
301→
302→	rawContent := bundle
303→	if rawContent == nil {
304→		rawContent = envelope
305→	}
306→
307→	// calculate the content digest
308→	// Todo: this should be calculated in the use case
309→	digest, _, err := v1.SHA256(bytes.NewReader(rawContent))
310→	if err != nil {
311→		return nil, fmt.Errorf("failed to calculate SHA256 of attestation: %w", err)
312→	}
313→
314→	dsseEnv, err := attestation.DSSEEnvelopeFromRaw(bundle, envelope)
315→	if err != nil {
316→		return nil, fmt.Errorf("extracting DSSE envelope: %w", err)
317→	}
318→
319→	// extract statement to run some validations in the content
320→	predicate, err := chainloop.ExtractPredicate(dsseEnv)
321→	if err != nil {
322→		return nil, fmt.Errorf("extracting predicate: %w", err)
323→	}
324→
325→	// verify attestation (only if chainloop is the signer)
326→	validation, err := uc.verifyBundle(ctx, rawContent)
327→	if err != nil {
328→		if !errors.Is(err, verifier.ErrInvalidBundle) {
329→			return nil, err
330→		}
331→		// invalid bundle is expected for old attestations so we skip validation
332→		uc.logger.Warn("received an old attestation format, not a bundle: attestation verification skipped", "error", err)
333→	}
334→
335→	// if it's verifiable, make sure it passed
336→	if validation != nil && !validation.Result {
337→		return nil, NewErrValidation(fmt.Errorf("attestation verification failed: %s", validation.FailureReason))
338→	}
339→
340→	// Run some validations on the predicate
341→	// Attestations can include dependent attestations, and we want to make sure they exist in the system
342→	// Find any material of kind attestation and make sure they exist already
343→	for _, m := range predicate.GetMaterials() {
344→		if m.Type == schemaapi.CraftingSchema_Material_ATTESTATION.String() {
345→			run, err := uc.wfRunRepo.FindByAttestationDigest(ctx, m.Hash.String())
346→			if err != nil {
347→				return nil, fmt.Errorf("finding attestation: %w", err)
348→			} else if run == nil {
349→				return nil, NewErrValidation(fmt.Errorf("dependent attestation not found: %s", m.Hash))
350→			}
351→		}
352→	}
353→
354→	// Save bundle if provided, as it might come as an empty struct
355→	if bundle != nil {
356→		// Save bundle
357→		if err = uc.wfRunRepo.SaveBundle(ctx, runID, bundle); err != nil {
358→			return nil, fmt.Errorf("saving bundle: %w", err)
359→		}
360→		// do not store the envelope if bundle is already stored
361→		dsseEnv = nil
362→	}
363→
364→	if err := uc.wfRunRepo.SaveAttestation(ctx, runID, dsseEnv, digest.String()); err != nil {
365→		return nil, fmt.Errorf("saving attestation: %w", err)
366→	}
367→
368→	// Extract and save policy violations status from the predicate
369→	var hasPolicyViolations bool
370→	if policyStatus := predicate.GetPolicyEvaluationStatus(); policyStatus != nil {
371→		hasPolicyViolations = policyStatus.HasViolations
372→	}
373→	if err := uc.wfRunRepo.UpdatePolicyViolationsStatus(ctx, runID, hasPolicyViolations); err != nil {
374→		return nil, fmt.Errorf("updating policy violations status: %w", err)
375→	}
376→
377→	return &digest, nil
378→}
