 27→
 28→// DefaultCursorLimit is the default number of items per page for cursor-based pagination
 29→const DefaultCursorLimit = 10
 30→
 31→// Cursor is a struct that holds the timestamp and identifier of a record
 32→type Cursor struct {
 33→	Timestamp *time.Time
 34→	ID        *uuid.UUID
 35→}
 36→
 37→// CursorOptions is a struct that holds the cursor and limit for pagination
 38→type CursorOptions struct {
 39→	Cursor *Cursor
 40→	Limit  int
 41→}
 42→
 43→// CursorPaginationError is the error type for cursor-based pagination
 44→type CursorPaginationError struct {
 45→	err error
 46→}
 47→
 48→// NewCursorPaginationError creates a new CursorPaginationError with the provided error
 49→func NewCursorPaginationError(err error) CursorPaginationError {
 50→	return CursorPaginationError{err}
 51→}
 52→
 53→// Error returns the error message
 54→func (e CursorPaginationError) Error() string {
 55→	return e.err.Error()
 56→}
 57→
 58→// IsCursorPaginationError checks if the error is an CursorPaginationError
 59→func IsCursorPaginationError(err error) bool {
 60→	return errors.As(err, &CursorPaginationError{})
 61→}
 62→
 63→func NewCursor(c string, l int) (*CursorOptions, error) {
 64→	var cursor *Cursor
 65→	var limit = DefaultCursorLimit
 66→
 67→	if c != "" {
 68→		timestamp, id, err := decodeCursor(c)
 69→		if err != nil {
 70→			return nil, NewCursorPaginationError(fmt.Errorf("decoding cursor: %w", err))
 71→		}
 72→		cursor = &Cursor{Timestamp: timestamp, ID: id}
 73→	}
 74→
 75→	if l > 0 {
 76→		limit = l
 77→	}
 78→
 79→	return &CursorOptions{
 80→		Cursor: cursor,
 81→		Limit:  limit,
 82→	}, nil
 83→}
 84→
 85→// decodeCursor decodes a base64 encoded cursor into a timestamp and identifier
 86→func decodeCursor(encodedCursor string) (*time.Time, *uuid.UUID, error) {
 87→	byt, err := base64.StdEncoding.DecodeString(encodedCursor)
 88→	if err != nil {
 89→		return nil, nil, err
 90→	}
 91→
 92→	arrStr := strings.Split(string(byt), ",")
 93→	if len(arrStr) != 2 {
 94→		return nil, nil, errors.New("cursor is invalid")
 95→	}
 96→
 97→	timestamp, err := time.Parse(time.RFC3339Nano, arrStr[0])
 98→	if err != nil {
 99→		return nil, nil, err
100→	}
101→
102→	rawID := arrStr[1]
103→	id, err := uuid.Parse(rawID)
104→	if err != nil {
105→		return nil, nil, err
106→	}
107→
108→	return &timestamp, &id, nil
109→}
110→
111→// EncodeCursor generates a base64 encoded representation of a timestamp + identifier
112→func EncodeCursor(t time.Time, uuid uuid.UUID) string {
113→	key := fmt.Sprintf("%s,%s", t.Format(time.RFC3339Nano), uuid)
114→	return base64.StdEncoding.EncodeToString([]byte(key))
115→}
