29→// OffsetPaginationError is the error type for page-based pagination
30→type OffsetPaginationError struct {
31→	err error
32→}
33→
34→// NewOffsetPaginationErrorStr creates a new OffsetPaginationError with the provided error message
35→func NewOffsetPaginationErrorStr(errMsg string) OffsetPaginationError {
36→	return OffsetPaginationError{errors.New(errMsg)}
37→}
38→
39→// Error returns the error message
40→func (e OffsetPaginationError) Error() string {
41→	return e.err.Error()
42→}
43→
44→// IsOffsetPaginationError checks if the error is an OffsetPaginationError
45→func IsOffsetPaginationError(err error) bool {
46→	return errors.As(err, &OffsetPaginationError{})
47→}
48→
49→// Unwrap returns the wrapped error
50→func (e OffsetPaginationError) Unwrap() error {
51→	return e.err
52→}
53→
54→// OffsetPaginationOpts is the options for page-based pagination
55→type OffsetPaginationOpts struct {
56→	// page is the page number
57→	page int
58→	// pageSize is the number of items per page
59→	pageSize int
60→}
61→
62→// NewDefaultOffsetPaginationOpts creates a new OffsetPaginationOpts with default values
63→func NewDefaultOffsetPaginationOpts() *OffsetPaginationOpts {
64→	return &OffsetPaginationOpts{
65→		page:     DefaultPage,
66→		pageSize: DefaultPageSize,
67→	}
68→}
69→
70→// Offset returns the page number
71→func (o *OffsetPaginationOpts) Offset() int {
72→	if o.page < 1 {
73→		o.page = 1
74→	}
75→	return (o.page - 1) * o.pageSize
76→}
77→
78→// Limit returns the number of items per page
79→func (o *OffsetPaginationOpts) Limit() int {
80→	return o.pageSize
81→}
82→
83→// NewOffsetPaginationOpts creates a new OffsetPaginationOpts with the provided page and pageSize
84→func NewOffsetPaginationOpts(offset, limit int) (*OffsetPaginationOpts, error) {
85→	if limit < 1 {
86→		return nil, NewOffsetPaginationErrorStr("pageSize must be greater than 0")
87→	}
88→
89→	if offset < 0 {
90→		return nil, NewOffsetPaginationErrorStr("page must be greater than or equal to 0")
91→	}
92→
93→	return &OffsetPaginationOpts{
94→		page:     offset,
95→		pageSize: limit,
96→	}, nil
97→}
