264→// List the runs in an organization, optionally filtered out by workflow
265→func (r *WorkflowRunRepo) List(ctx context.Context, orgID uuid.UUID, filters *biz.RunListFilters, p *pagination.CursorOptions) (result []*biz.WorkflowRun, cursor string, err error) {
266→	if p == nil {
267→		return nil, "", errors.New("pagination options is required")
268→	}
269→
270→	// workflow filters
271→	wfPredicates := []predicate.Workflow{
272→		workflow.DeletedAtIsNil(),
273→		workflow.OrganizationID(orgID),
274→	}
275→	if filters.ProjectIDs != nil {
276→		wfPredicates = append(wfPredicates, workflow.ProjectIDIn(filters.ProjectIDs...))
277→	}
278→
279→	// query first for workflows to avoid joining the workflow_runs table
280→	wfExist, err := r.data.DB.Workflow.Query().Where(wfPredicates...).Exist(ctx)
281→	if err != nil {
282→		return nil, "", fmt.Errorf("getting workflows: %w", err)
283→	}
284→	if !wfExist {
285→		// No workflows in the org, no runs
286→		return nil, "", nil
287→	}
288→
289→	// Query workflow runs by joining with workflows
290→	q := r.data.DB.WorkflowRun.Query().Where(
291→		workflowrun.HasWorkflowWith(wfPredicates...)).
292→		Order(ent.Desc(workflowrun.FieldCreatedAt)).
293→		WithWorkflowAndProject().WithVersion().
294→		Limit(p.Limit + 1)
295→
296→	// Append the workflow filter if present
297→	if filters != nil && filters.WorkflowID != nil {
298→		q = q.Where(workflowrun.HasWorkflowWith(workflow.ID(*filters.WorkflowID)))
299→	}
300→
301→	// Append the state filter if present, i.e only running
302→	if filters != nil && filters.Status != "" {
303→		q = q.Where(workflowrun.StateEQ(filters.Status))
304→	}
305→
306→	// or the project version
307→	if filters != nil && filters.VersionID != nil {
308→		q = q.Where(workflowrun.VersionID(*filters.VersionID))
309→	}
310→
311→	// Append the policy violations filter if present
312→	if filters != nil && filters.PolicyViolationsFilter != nil {
313→		if *filters.PolicyViolationsFilter {
314→			// Filter for runs WITH violations (has_policy_violations = true)
315→			q = q.Where(workflowrun.HasPolicyViolations(true))
316→		} else {
317→			// Filter for runs WITHOUT violations (has_policy_violations = false)
318→			q = q.Where(workflowrun.HasPolicyViolations(false))
319→		}
320→	}
321→
322→	if p.Cursor != nil {
323→		q = q.Where(
324→			func(s *sql.Selector) {
325→				s.Where(sql.CompositeLT([]string{s.C(workflowrun.FieldCreatedAt), s.C(workflowrun.FieldID)}, p.Cursor.Timestamp, p.Cursor.ID))
326→			})
327→	}
328→
329→	workflowRuns, err := q.All(ctx)
330→	if err != nil {
331→		return nil, "", err
332→	}
333→
334→	for i, wr := range workflowRuns {
335→		// Check if there are additional items for another page
336→		// if so, set the cursor to the last item in the window
337→		if i == p.Limit {
338→			prevwr := workflowRuns[i-1]
339→			cursor = pagination.EncodeCursor(prevwr.CreatedAt, prevwr.ID)
340→			continue
341→		}
342→
343→		r, err := entWrToBizWr(ctx, wr)
344→		if err != nil {
345→			return nil, "", fmt.Errorf("failed to convert workflow run: %w", err)
346→		}
347→		result = append(result, r)
348→	}
349→
350→	return result, cursor, nil
351→}
