353→func (r *WorkflowRunRepo) ListNotFinishedOlderThan(ctx context.Context, olderThan time.Time, limit int) ([]*biz.WorkflowRun, error) {
354→	q := r.data.DB.WorkflowRun.Query().WithWorkflow().Where(workflowrun.CreatedAtLTE(olderThan)).Where(workflowrun.StateEQ(biz.WorkflowRunInitialized))
355→	if limit > 0 {
356→		q = q.Limit(limit)
357→	}
358→
359→	// TODO: Look into adding upper bound on the createdAt column to prevent full table scans
360→	// For now this is fine especially because we have a composite index
361→	workflowRuns, err := q.All(ctx)
362→	if err != nil {
363→		return nil, err
364→	}
365→
366→	result := make([]*biz.WorkflowRun, 0, len(workflowRuns))
367→	for _, wr := range workflowRuns {
368→		r, err := entWrToBizWr(ctx, wr)
369→		if err != nil {
370→			return nil, fmt.Errorf("failed to convert workflow run: %w", err)
371→		}
372→
373→		result = append(result, r)
374→	}
375→
376→	return result, nil
377→}
