383→func entWrToBizWr(ctx context.Context, wr *ent.WorkflowRun) (*biz.WorkflowRun, error) {
384→	r := &biz.WorkflowRun{
385→		ID:                     wr.ID,
386→		CreatedAt:              toTimePtr(wr.CreatedAt),
387→		FinishedAt:             toTimePtr(wr.FinishedAt),
388→		State:                  string(wr.State),
389→		Reason:                 wr.Reason,
390→		RunURL:                 wr.RunURL,
391→		RunnerType:             wr.RunnerType,
392→		CASBackends:            make([]*biz.CASBackend, 0),
393→		ContractRevisionUsed:   wr.ContractRevisionUsed,
394→		ContractRevisionLatest: wr.ContractRevisionLatest,
395→		HasPolicyViolations:    wr.HasPolicyViolations,
396→		Attestation: &biz.Attestation{
397→			Digest: wr.AttestationDigest,
398→		},
399→	}
400→
401→	if wr.Attestation != nil {
402→		r.Attestation.Envelope = wr.Attestation
403→	}
404→
405→	if cv := wr.Edges.ContractVersion; cv != nil {
406→		r.ContractVersionID = cv.ID
407→	}
408→
409→	if wf := wr.Edges.Workflow; wf != nil {
410→		w, err := entWFToBizWF(ctx, wf)
411→		if err != nil {
412→			return nil, fmt.Errorf("failed to convert workflow: %w", err)
413→		}
414→
415→		r.Workflow = w
416→	}
417→
418→	// Load version preloaded or otherwise query it
419→	if wr.Edges.Version != nil {
420→		r.ProjectVersion = entProjectVersionToBiz(wr.Edges.Version)
421→	}
422→
423→	if backends := wr.Edges.CasBackends; backends != nil {
424→		for _, b := range backends {
425→			r.CASBackends = append(r.CASBackends, entCASBackendToBiz(b))
426→		}
427→	}
428→
429→	return r, nil
430→}
