 77→
 78→	// by workflow and project name
 79→	if req.GetWorkflowName() != "" && req.GetProjectName() != "" {
 80→		wf, err := s.workflowUseCase.FindByNameInOrg(ctx, currentOrg.ID, req.GetProjectName(), req.GetWorkflowName())
