 86→
 87→		filters.WorkflowID = &wf.ID
 88→	} else if req.GetProjectName() != "" {
 89→		// by project name only
 90→		projectID, err := s.validateAndGetProjectID(ctx, currentOrg.ID, req.GetProjectName(), visibleProjectIDs)
 91→		if err != nil {
 92→			return nil, handleUseCaseErr(err, s.log)
 93→		}
 94→
 95→		// Override the filter to only include this specific project
 96→		filters.ProjectIDs = []uuid.UUID{projectID}
