107→
108→	// by run status
109→	if req.GetStatus() != pb.RunStatus_RUN_STATUS_UNSPECIFIED {
110→		st, err := pbWorkflowRunStatusToBiz(req.GetStatus())
111→		if err != nil {
112→			return nil, errors.BadRequest("invalid run status", err.Error())
113→		}
114→		filters.Status = st
115→	}
116→
117→	// by policy violations status
118→	if req.GetPolicyViolations() != pb.REDACTED {
119→		hasViolations := req.GetPolicyViolations() == pb.PolicyViolationsFilter_POLICY_VIOLATIONS_FILTER_WITH_VIOLATIONS
120→		filters.PolicyViolationsFilter = &hasViolations
121→	}
122→
123→	p := req.GetPagination()
124→	paginationOpts, err := pagination.NewCursor(p.GetCursor(), int(p.GetLimit()))
125→	if err != nil {
126→		return nil, errors.InternalServer("invalid", "invalid pagination options")
127→	}
128→
129→	workflowRuns, nextCursor, err := s.wrUseCase.List(ctx, currentOrg.ID, filters, paginationOpts)
130→	if err != nil {
131→		return nil, handleUseCaseErr(err, s.log)
132→	}
