148→func (s *WorkflowRunService) View(ctx context.Context, req *pb.WorkflowRunServiceViewRequest) (*pb.WorkflowRunServiceViewResponse, error) {
149→	currentOrg, err := requireCurrentOrg(ctx)
150→	if err != nil {
151→		return nil, err
152→	}
153→
154→	// retrieve the workflow run either by ID or by digest
155→	var run *biz.WorkflowRun
156→	switch {
157→	case req.GetId() != "":
158→		run, err = s.wrUseCase.GetByIDInOrgOrPublic(ctx, currentOrg.ID, req.GetId())
159→		if err != nil {
160→			return nil, handleUseCaseErr(err, s.log)
161→		}
162→	case req.GetDigest() != "":
163→		run, err = s.wrUseCase.GetByDigestInOrgOrPublic(ctx, currentOrg.ID, req.GetDigest())
164→		if err != nil {
165→			return nil, handleUseCaseErr(err, s.log)
166→		}
167→	default:
168→		return nil, errors.BadRequest("invalid", "id or digest required")
169→	}
170→
171→	// Apply RBAC only if workflow is not public
172→	if !run.Workflow.Public {
173→		if err = s.authorizeResource(ctx, authz.PolicyWorkflowRunRead, authz.ResourceTypeProject, run.Workflow.ProjectID); err != nil {
174→			return nil, err
175→		}
176→	}
177→
178→	var verificationResult *pb.WorkflowRunServiceViewResponse_VerificationResult
179→	if req.Verify {
180→		// it might be nil if it doesn't apply
181→		vr, err := s.wrUseCase.VerifyRun(ctx, run)
182→		if err != nil {
183→			return nil, handleUseCaseErr(err, s.log)
184→		}
185→		verificationResult = bizVerificationToPb(vr)
186→	}
187→
188→	attestation, err := bizAttestationToPb(run.Attestation)
189→	if err != nil {
190→		return nil, handleUseCaseErr(err, s.log)
191→	}
192→
193→	contractAndVersion, err := s.workflowContractUseCase.FindVersionByID(ctx, run.ContractVersionID.String())
194→	if err != nil {
195→		return nil, handleUseCaseErr(err, s.log)
196→	}
197→
198→	wr := bizWorkFlowRunToPb(run)
199→	wr.Workflow = bizWorkflowToPb(run.Workflow)
200→	wr.ContractVersion = bizWorkFlowContractVersionToPb(contractAndVersion.Version, contractAndVersion.Contract)
201→	wr.ContractVersion.ContractName = contractAndVersion.Contract.Name
202→	res := &pb.WorkflowRunServiceViewResponse_Result{
203→		OrgName:      currentOrg.Name,
204→		WorkflowRun:  wr,
205→		Attestation:  attestation,
206→		Verification: verificationResult,
207→	}
208→
209→	return &pb.WorkflowRunServiceViewResponse{Result: res}, nil
210→}
