28→message CursorPaginationRequest {
29→  string cursor = 1;
30→  // Limit pagination to 100
31→  int32 limit = 3 [
32→    (buf.validate.field).int32 = {
33→      gte: 1
34→      lte: 100
35→    },
36→    (buf.validate.field).ignore = IGNORE_IF_ZERO_VALUE
37→  ];
38→}
39→
40→// OffsetPaginationRequest is used to paginate the results
41→message OffsetPaginationRequest {
42→  // The (zero-based) offset of the first item returned in the collection.
43→  int32 page = 1 [(buf.validate.field).int32.gte = 1];
44→  // The maximum number of entries to return. If the value exceeds the maximum, then the maximum value will be used.
45→  int32 page_size = 2 [
46→    (buf.validate.field).int32.gt = 0,
47→    (buf.validate.field).int32.lte = 100
48→  ];
49→}
50→
51→// OffsetPaginationResponse is used to return the pagination information
52→message OffsetPaginationResponse {
53→  // The current page number
54→  int32 page = 1;
55→  // The number of results per page
56→  int32 page_size = 2;
57→  // The total number of results
58→  int32 total_count = 3;
59→  // The total number of pages
60→  int32 total_pages = 4;
61→}
