 16→syntax = "proto3";
 17→
 18→package controlplane.v1;
 19→
 20→import "buf/validate/validate.proto";
 21→import "controlplane/v1/pagination.proto";
 22→import "controlplane/v1/response_messages.proto";
 23→import "workflowcontract/v1/crafting_schema.proto";
 24→
 25→option go_package = "github.com/chainloop-dev/chainloop/app/controlplane/api/controlplane/v1;v1";
 26→
 27→// This service is used by the CLI to generate attestation
 28→service AttestationService {
 29→  rpc FindOrCreateWorkflow(FindOrCreateWorkflowRequest) returns (FindOrCreateWorkflowResponse);
 30→  rpc GetContract(AttestationServiceGetContractRequest) returns (AttestationServiceGetContractResponse);
 31→  rpc Init(AttestationServiceInitRequest) returns (AttestationServiceInitResponse);
 32→  rpc Store(AttestationServiceStoreRequest) returns (AttestationServiceStoreResponse);
 33→  // There is another endpoint to get credentials via casCredentialsService.Get
 34→  // This one is kept since it leverages robot-accounts in the context of a workflow
 35→  rpc GetUploadCreds(AttestationServiceGetUploadCredsRequest) returns (AttestationServiceGetUploadCredsResponse);
 36→  rpc Cancel(AttestationServiceCancelRequest) returns (AttestationServiceCancelResponse);
 37→
 38→  // Get policies from remote providers
 39→  rpc GetPolicy(AttestationServiceGetPolicyRequest) returns (AttestationServiceGetPolicyResponse);
 40→  rpc GetPolicyGroup(AttestationServiceGetPolicyGroupRequest) returns (AttestationServiceGetPolicyGroupResponse);
 41→}
 42→
 43→// Administrative service for the operator
 44→service WorkflowRunService {
 45→  rpc List(WorkflowRunServiceListRequest) returns (WorkflowRunServiceListResponse);
 46→  rpc View(WorkflowRunServiceViewRequest) returns (WorkflowRunServiceViewResponse);
 47→}
 48→
 49→message FindOrCreateWorkflowRequest {
 50→  string workflow_name = 4 [(buf.validate.field).string.min_len = 1];
 51→  string project_name = 5 [(buf.validate.field).string.min_len = 1];
 52→  // name of an existing contract
 53→  string contract_name = 6;
 54→  // raw contract bytes that can be used to create or update the contract
 55→  bytes contract_bytes = 7;
 56→}
 57→
 58→message FindOrCreateWorkflowResponse {
 59→  WorkflowItem result = 1;
 60→}
 61→
 62→message AttestationServiceGetPolicyRequest {
 63→  // Provider name. If not set, the default provider will be used
 64→  string provider = 1;
 65→
 66→  // Policy name (it must exist in the provider)
 67→  string policy_name = 2 [(buf.validate.field).string.min_len = 1];
 68→
 69→  // The org owning this policy
 70→  string org_name = 3;
 71→}
 72→
 73→message AttestationServiceGetPolicyResponse {
 74→  workflowcontract.v1.Policy policy = 1;
 75→  // FQDN of the policy in the provider
 76→  RemotePolicyReference reference = 2;
 77→}
 78→
 79→message RemotePolicyReference {
 80→  string url = 1;
 81→  string digest = 2;
 82→}
 83→
 84→message AttestationServiceGetPolicyGroupRequest {
 85→  // Provider name. If not set, the default provider will be used
 86→  string provider = 1;
 87→
 88→  // Group name (it must exist in the provider)
 89→  string group_name = 2 [(buf.validate.field).string.min_len = 1];
 90→
 91→  // The org owning this group
 92→  string org_name = 3;
 93→}
 94→
 95→message AttestationServiceGetPolicyGroupResponse {
 96→  workflowcontract.v1.PolicyGroup group = 1;
 97→  // FQDN of the policy in the provider
 98→  RemotePolicyReference reference = 2;
 99→}
100→
101→message AttestationServiceGetContractRequest {
102→  int32 contract_revision = 1;
103→  string workflow_name = 2 [(buf.validate.field).string.min_len = 1];
104→  string project_name = 3 [(buf.validate.field).string.min_len = 1];
105→}
106→
107→message AttestationServiceGetContractResponse {
108→  Result result = 1;
109→
110→  message Result {
111→    WorkflowItem workflow = 1;
112→    WorkflowContractVersionItem contract = 2;
113→  }
114→}
115→
116→message AttestationServiceInitRequest {
117→  int32 contract_revision = 1;
118→  string job_url = 2;
119→  workflowcontract.v1.CraftingSchema.Runner.RunnerType runner = 3;
120→  string workflow_name = 4 [(buf.validate.field).string.min_len = 1];
121→  string project_name = 5 [(buf.validate.field).string.min_len = 1];
122→
123→  // Optional project version
124→  string project_version = 6;
125→  // Optional flag to require that the project version already exists
126→  bool require_existing_version = 7;
127→}
128→
129→message AttestationServiceInitResponse {
130→  Result result = 1;
131→
132→  message Result {
133→    WorkflowRunItem workflow_run = 2;
134→    // organization name
135→    string organization = 3;
136→    // fail the attestation if there is a violation in any policy
137→    bool block_on_policy_violation = 4;
138→    // Signing options
139→    SigningOptions signing_options = 5;
140→    // array of hostnames that are allowed to be used in the policies
141→    repeated string policies_allowed_hostnames = 6;
142→    // URL pointing to the web dashboard. It might be empty if not available
143→    string ui_dashboard_url = 7;
144→    // Whether AI agent config collection is enabled at the org level
145→    bool enable_ai_agent_collector = 8;
146→  }
147→
148→  message SigningOptions {
149→    // TSA service to be used for signing
150→    string timestamp_authority_url = 1;
151→    // If set, the attestation wil be signed with ephemeral certificates issued by this CA
152→    string signing_ca = 2;
153→  }
154→}
155→
156→message AttestationServiceStoreRequest {
157→  // encoded DSEE envelope
158→  bytes attestation = 1 [deprecated = true];
159→  // deprecated because of https://github.com/chainloop-dev/chainloop/issues/1832
160→  bytes bundle = 4 [deprecated = true];
161→  // encoded Sigstore attestation bundle
162→  bytes attestation_bundle = 5;
163→
164→  string workflow_run_id = 2 [(buf.validate.field).string = {min_len: 1}];
165→  // mark the associated version as released
166→  optional bool mark_version_as_released = 3;
167→}
168→
169→message AttestationServiceStoreResponse {
170→  Result result = 1;
171→
172→  message Result {
173→    // attestation digest
174→    string digest = 2;
175→  }
176→}
177→
178→message AttestationServiceCancelRequest {
179→  string workflow_run_id = 1 [(buf.validate.field).string = {min_len: 1}];
180→  TriggerType trigger = 2 [(buf.validate.field).enum = {
181→    not_in: [0]
182→  }];
183→  string reason = 3;
184→
185→  enum TriggerType {
186→    TRIGGER_TYPE_UNSPECIFIED = 0;
187→    TRIGGER_TYPE_FAILURE = 1;
188→    TRIGGER_TYPE_CANCELLATION = 2;
189→  }
190→}
191→
192→message AttestationServiceCancelResponse {}
193→
194→message WorkflowRunServiceListRequest {
195→  // Filters
196→  // by workflow
197→  string workflow_name = 1 [(buf.validate.field) = {
198→    ignore: IGNORE_IF_ZERO_VALUE
199→    cel: {
200→      message: "must contain only lowercase letters, numbers, and hyphens."
201→      expression: "this.matches('^[a-z0-9]([-a-z0-9]*[a-z0-9])?$')"
202→      id: "name.dns-1123"
203→    }
204→  }];
205→
206→  // Not required since filtering by workflow and project is optional
207→  string project_name = 4;
208→  // by run status
209→  RunStatus status = 3;
210→  // by project version
211→  string project_version = 5 [(buf.validate.field) = {
212→    string: {uuid: true}
213→    ignore: IGNORE_IF_ZERO_VALUE
214→  }];
215→  // by policy violations status
216→  PolicyViolationsFilter policy_violations = 6;
217→  // pagination options
218→  CursorPaginationRequest pagination = 2;
219→
220→  // Custom validation to ensure project_name is set if workflow_name is set
221→  option (buf.validate.message).cel = {
222→    id: "workflow_project_dependency"
223→    expression: "!(this.workflow_name != '' && this.project_name == '')"
224→    message: "project_name must be set if workflow_name is set"
225→  };
226→}
227→
228→message WorkflowRunServiceListResponse {
229→  repeated WorkflowRunItem result = 1;
230→  CursorPaginationResponse pagination = 2;
231→}
232→
233→message WorkflowRunServiceViewRequest {
234→  // It can search by either ID or digest
235→  oneof ref {
236→    option (buf.validate.oneof).required = true;
237→
238→    string id = 1 [(buf.validate.field).string.uuid = true];
239→    string digest = 2 [(buf.validate.field).string = {min_len: 1}];
240→  }
241→  // run verification
242→  bool verify = 3;
243→}
244→
245→message WorkflowRunServiceViewResponse {
246→  Result result = 1;
247→
248→  message Result {
249→    string org_name = 5;
250→    WorkflowRunItem workflow_run = 1;

