152→// ExtractAndPersist extracts the referrers (subject + materials) from the given attestation
153→// and store it as part of the referrers index table
154→func (s *ReferrerUseCase) ExtractAndPersist(ctx context.Context, att *dsse.Envelope, digest cr_v1.Hash, workflowID string) error {
155→	workflowUUID, err := uuid.Parse(workflowID)
156→	if err != nil {
157→		return NewErrInvalidUUID(err)
158→	}
159→
160→	// Check that the workflow belongs to the organization
161→	if wf, err := s.workflowRepo.FindByID(ctx, workflowUUID); err != nil {
162→		return fmt.Errorf("finding workflow: %w", err)
163→	} else if wf == nil {
164→		return NewErrNotFound("workflow")
165→	}
166→
167→	referrers, err := extractReferrers(att, digest, s.repo)
168→	if err != nil {
169→		return fmt.Errorf("extracting referrers: %w", err)
170→	}
171→
172→	if err := s.repo.Save(ctx, referrers, workflowUUID); err != nil {
173→		return fmt.Errorf("saving referrers: %w", err)
174→	}
175→
176→	return nil
177→}
