	}

	return pbReferrerItemToAction(resp.Result), nil
}

func pbReferrerItemToAction(in *pb.ReferrerItem) *ReferrerItem {
	if in == nil {
		return nil
	}

	out := &ReferrerItem{
		Digest:       in.GetDigest(),
		Downloadable: in.GetDownloadable(),
		Public:       in.GetPublic(),
		Kind:         in.GetKind(),
		CreatedAt:    toTimePtr(in.GetCreatedAt().AsTime()),
