func (r *WorkflowRunRepo) List(ctx context.Context, orgID uuid.UUID, filters *biz.RunListFilters, p *pagination.CursorOptions) (result []*biz.WorkflowRun, cursor string, err error) {
	if p == nil {
		return nil, "", errors.New("pagination options is required")
	}

	// workflow filters
	wfPredicates := []predicate.Workflow{
		workflow.DeletedAtIsNil(),
		workflow.OrganizationID(orgID),
	}
	if filters.ProjectIDs != nil {
		wfPredicates = append(wfPredicates, workflow.ProjectIDIn(filters.ProjectIDs...))
	}

	// query first for workflows to avoid joining the workflow_runs table
	wfExist, err := r.data.DB.Workflow.Query().Where(wfPredicates...).Exist(ctx)
	if err != nil {
		return nil, "", fmt.Errorf("getting workflows: %w", err)
	}
	if !wfExist {
		// No workflows in the org, no runs
		return nil, "", nil
	}

	// Query workflow runs by joining with workflows
	q := r.data.DB.WorkflowRun.Query().Where(
		workflowrun.HasWorkflowWith(wfPredicates...)).
		Order(ent.Desc(workflowrun.FieldCreatedAt)).
		WithWorkflowAndProject().WithVersion().
		Limit(p.Limit + 1)

	// Append the workflow filter if present
	if filters != nil && filters.WorkflowID != nil {
		q = q.Where(workflowrun.HasWorkflowWith(workflow.ID(*filters.WorkflowID)))
	}

	// Append the state filter if present, i.e only running
	if filters != nil && filters.Status != "" {
		q = q.Where(workflowrun.StateEQ(filters.Status))
	}

	// or the project version
	if filters != nil && filters.VersionID != nil {
		q = q.Where(workflowrun.VersionID(*filters.VersionID))
	}

	// Append the policy violations filter if present
	if filters != nil && filters.PolicyViolationsFilter != nil {
		if *filters.PolicyViolationsFilter {
			// Filter for runs WITH violations (has_policy_violations = true)
			q = q.Where(workflowrun.HasPolicyViolations(true))
		} else {
			// Filter for runs WITHOUT violations (has_policy_violations = false)
			q = q.Where(workflowrun.HasPolicyViolations(false))
		}
	}

	if p.Cursor != nil {
		q = q.Where(
			func(s *sql.Selector) {
				s.Where(sql.CompositeLT([]string{s.C(workflowrun.FieldCreatedAt), s.C(workflowrun.FieldID)}, p.Cursor.Timestamp, p.Cursor.ID))
			})
	}

	workflowRuns, err := q.All(ctx)
	if err != nil {
		return nil, "", err
	}

	for i, wr := range workflowRuns {
		// Check if there are additional items for another page
		// if so, set the cursor to the last item in the window
		if i == p.Limit {
			prevwr := workflowRuns[i-1]
			cursor = pagination.EncodeCursor(prevwr.CreatedAt, prevwr.ID)
			continue
		}

		r, err := entWrToBizWr(ctx, wr)
		if err != nil {
			return nil, "", fmt.Errorf("failed to convert workflow run: %w", err)
		}
		result = append(result, r)
	}

	return result, cursor, nil
}

