		orgUUID, err := uuid.Parse(orgID)
		if err != nil {
			return nil, NewErrInvalidUUID(err)
		}
		orgIDs = append(orgIDs, orgUUID)
	}

	// and ask only for the public referrers of those orgs
	filters := []GetFromRootFilter{WithPublicVisibility(true)}
	if rootKind != "" {
