 27→// WorkflowRunStatus represents the status of a workflow run
 28→var WorkflowRunStatus = func() map[string]pb.RunStatus {
 29→	res := make(map[string]pb.RunStatus)
 30→	for k, v := range pb.RunStatus_value {
 31→		if k != "RUN_STATUS_UNSPECIFIED" {
 32→			res[strings.Replace(k, "RUN_STATUS_", "", 1)] = pb.RunStatus(v)
 33→		}
 34→	}
 35→	return res
 36→}
