 38→type WorkflowRunList struct {
 39→	cfg *ActionsOpts
 40→}
 41→
 42→type WorkflowRunItem struct {
 43→	ID                     string                       `json:"id"`
 44→	State                  string                       `json:"state"`
 45→	Reason                 string                       `json:"reason,omitempty"`
 46→	CreatedAt              *time.Time                   `json:"createdAt,omitempty"`
 47→	FinishedAt             *time.Time                   `json:"finishedAt,omitempty"`
 48→	Workflow               *WorkflowItem                `json:"workflow,omitempty"`
 49→	RunURL                 string                       `json:"runURL,omitempty"`
 50→	RunnerType             string                       `json:"runnerType,omitempty"`
 51→	ContractVersion        *WorkflowContractVersionItem `json:"contractVersion,omitempty"`
 52→	ContractRevisionUsed   int                          `json:"contractRevisionUsed"`
 53→	ContractRevisionLatest int                          `json:"contractRevisionLatest"`
 54→	ProjectVersion         *ProjectVersion              `json:"projectVersion,omitempty"`
 55→	PolicyStatus           string                       `json:"policyStatus,omitempty"`
 56→}
 57→
 58→type ProjectVersion struct {
 59→	ID             string `json:"id"`
 60→	Version        string `json:"version,omitempty"`
 61→	Prerelease     bool   `json:"prerelease"`
 62→	MarkAsReleased bool   `json:"markAsRelease"`
 63→}
 64→
 65→type PaginatedWorkflowRunItem struct {
 66→	Result         []*WorkflowRunItem
 67→	PaginationMeta *PaginationOpts
 68→}
 69→
 70→func NewWorkflowRunList(cfg *ActionsOpts) *WorkflowRunList {
 71→	return &WorkflowRunList{cfg}
 72→}
 73→
 74→type WorkflowRunListOpts struct {
 75→	WorkflowName, ProjectName string
 76→	Pagination                *PaginationOpts
 77→	Status                    string
 78→	PolicyStatus              string
 79→}
 80→type PaginationOpts struct {
 81→	Limit      int
 82→	NextCursor string
 83→}
 84→
 85→func (action *WorkflowRunList) Run(opts *WorkflowRunListOpts) (*PaginatedWorkflowRunItem, error) {
 86→	client := pb.NewWorkflowRunServiceClient(action.cfg.CPConnection)
 87→	req := &pb.WorkflowRunServiceListRequest{
 88→		WorkflowName: opts.WorkflowName,
 89→		ProjectName:  opts.ProjectName,
 90→		Pagination: &pb.CursorPaginationRequest{
 91→			Limit:  int32(opts.Pagination.Limit),
 92→			Cursor: opts.Pagination.NextCursor,
 93→		},
 94→	}
 95→
 96→	if v, ok := WorkflowRunStatus()[opts.Status]; ok {
 97→		req.Status = v
 98→	}
 99→
100→	// Map policy status string to proto enum
101→	if opts.PolicyStatus != "" {
102→		switch opts.PolicyStatus {
103→		case "failed":
104→			req.PolicyViolations = pb.PolicyViolationsFilter_POLICY_VIOLATIONS_FILTER_WITH_VIOLATIONS
105→		case "passed":
106→			req.PolicyViolations = pb.REDACTED
107→		case "all":
108→			req.PolicyViolations = pb.REDACTED
109→		}
110→	}
111→
112→	resp, err := client.List(context.Background(), req)
113→	if err != nil {
114→		return nil, err
115→	}
116→
117→	result := make([]*WorkflowRunItem, 0, len(resp.Result))
118→	for _, p := range resp.Result {
119→		result = append(result, pbWorkflowRunItemToAction(p))
120→	}
121→
122→	res := &PaginatedWorkflowRunItem{
123→		Result: result,
124→		PaginationMeta: &PaginationOpts{
125→			NextCursor: resp.GetPagination().GetNextCursor(),
126→		},
127→	}
128→
129→	return res, nil
130→}
131→
132→func humanizedRunStatus(in pb.RunStatus) string {
133→	mapping := map[pb.RunStatus]string{
134→		pb.RunStatus_RUN_STATUS_UNSPECIFIED: "unspecified",
135→		pb.RunStatus_RUN_STATUS_INITIALIZED: "in progress",
136→		pb.RunStatus_RUN_STATUS_SUCCEEDED:   "success",
137→		pb.RunStatus_RUN_STATUS_FAILED:      "failed",
138→		pb.RunStatus_RUN_STATUS_CANCELLED:   "canceled",
139→		pb.RunStatus_RUN_STATUS_EXPIRED:     "expired",
140→	}
141→
142→	return mapping[in]
143→}
144→
145→func pbWorkflowRunItemToAction(in *pb.WorkflowRunItem) *WorkflowRunItem {
146→	if in == nil {
147→		return nil
148→	}
149→
150→	item := &WorkflowRunItem{
151→		ID: in.Id, State: humanizedRunStatus(in.GetStatus()), Reason: in.Reason, CreatedAt: toTimePtr(in.CreatedAt.AsTime()),
152→		Workflow:               pbWorkflowItemToAction(in.Workflow),
153→		RunURL:                 in.GetJobUrl(),
154→		RunnerType:             humanizedRunnerType(in.GetRunnerType()),
155→		ContractRevisionUsed:   int(in.GetContractRevisionUsed()),
156→		ContractRevisionLatest: int(in.GetContractRevisionLatest()),
157→		ProjectVersion: &ProjectVersion{
158→			ID:         in.GetVersion().GetId(),
159→			Version:    in.GetVersion().GetVersion(),
160→			Prerelease: in.GetVersion().GetPrerelease(),
161→		},
162→		PolicyStatus: humanizedPolicyStatus(in.HasPolicyViolations),
163→	}
164→
165→	if in.GetContractVersion() != nil {
166→		item.ContractVersion = pbWorkflowContractVersionItemToAction(in.GetContractVersion())
167→	}
168→
169→	if in.FinishedAt != nil {
170→		item.FinishedAt = toTimePtr(in.FinishedAt.AsTime())
171→	}
172→
173→	return item
174→}
175→
176→func humanizedPolicyStatus(hasPolicyViolations *bool) string {
177→	if hasPolicyViolations == nil {
178→		return "N/A"
179→	}
180→	if *hasPolicyViolations {
181→		return "failed"
182→	}
183→	return "passed"
184→}
185→
186→func humanizedRunnerType(in v1.CraftingSchema_Runner_RunnerType) string {
187→	mapping := map[v1.CraftingSchema_Runner_RunnerType]string{
188→		*v1.CraftingSchema_Runner_RUNNER_TYPE_UNSPECIFIED.Enum(): "Unspecified",
189→		*v1.REDACTED.Enum():           "GitHub",
190→		*v1.CraftingSchema_Runner_GITLAB_PIPELINE.Enum():         "GitLab",
191→		*v1.CraftingSchema_Runner_AZURE_PIPELINE.Enum():          "Azure Pipeline",
192→		*v1.CraftingSchema_Runner_JENKINS_JOB.Enum():             "Jenkins Job",
193→		*v1.CraftingSchema_Runner_CIRCLECI_BUILD.Enum():          "CircleCI Build",
194→		*v1.CraftingSchema_Runner_DAGGER_PIPELINE.Enum():         "Dagger Pipeline",
195→		*v1.CraftingSchema_Runner_TEAMCITY_PIPELINE.Enum():       "TeamCity Pipeline",
196→		*v1.CraftingSchema_Runner_TEKTON_PIPELINE.Enum():         "Tekton Pipeline",
197→	}
198→
199→	hrt, ok := mapping[in]
200→	if !ok {
201→		return "Unknown"
202→	}
203→
204→	return hrt
205→}
