251→func pbWorkflowRunStatusToBiz(st pb.RunStatus) (biz.WorkflowRunStatus, error) {
252→	m := map[pb.RunStatus]biz.WorkflowRunStatus{
253→		pb.RunStatus_RUN_STATUS_INITIALIZED: biz.WorkflowRunInitialized,
254→		pb.RunStatus_RUN_STATUS_SUCCEEDED:   biz.WorkflowRunSuccess,
255→		pb.RunStatus_RUN_STATUS_FAILED:      biz.WorkflowRunError,
256→		pb.RunStatus_RUN_STATUS_EXPIRED:     biz.WorkflowRunExpired,
257→		pb.RunStatus_RUN_STATUS_CANCELLED:   biz.WorkflowRunCancelled,
258→	}
259→
260→	// not in the list
261→	if _, ok := m[st]; !ok {
262→		return "", fmt.Errorf("invalid run status: %s", st.String())
263→	}
264→
265→	return m[st], nil
266→}
