307→// validateAndGetProjectID finds a project by name and verifies it's in the visible projects list
308→func (s *WorkflowRunService) validateAndGetProjectID(ctx context.Context, orgID, projectName string, visibleProjectIDs []uuid.UUID) (uuid.UUID, error) {
309→	project, err := s.projectUseCase.FindProjectByReference(ctx, orgID, &biz.IdentityReference{Name: &projectName})
310→	if err != nil {
311→		return uuid.Nil, err
312→	} else if project == nil {
313→		return uuid.Nil, biz.NewErrNotFound("project")
314→	}
315→
316→	// Check if the project is in the visible projects list (RBAC)
317→	// nil means all projects are visible
318→	if visibleProjectIDs != nil && !slices.Contains(visibleProjectIDs, project.ID) {
319→		return uuid.Nil, biz.NewErrNotFound("project")
320→	}
321→
322→	return project.ID, nil
323→}
