 43→func (s *ReferrerService) DiscoverPrivate(ctx context.Context, req *pb.ReferrerServiceDiscoverPrivateRequest) (*pb.ReferrerServiceDiscoverPrivateResponse, error) {
 44→	currentUser, currentToken, err := requireCurrentUserOrAPIToken(ctx)
 45→	if err != nil {
 46→		return nil, err
 47→	}
 48→
 49→	currentOrg, err := requireCurrentOrg(ctx)
 50→	if err != nil {
 51→		return nil, err
 52→	}
 53→
 54→	paginationOpts, err := referrerPaginationOptsFromProto(req.GetPagination())
 55→	if err != nil {
 56→		return nil, err
 57→	}
 58→
 59→	// if we are logged in as user we find the referrer from the user
 60→	// otherwise for the current organization associated with the API token
 61→	var referrer *biz.StoredReferrer
 62→	var nextCursor string
 63→	if currentUser != nil {
 64→		referrer, nextCursor, err = s.referrerUC.GetFromRootUser(ctx, req.GetDigest(), req.GetKind(), currentUser.ID, paginationOpts)
 65→	} else if currentToken != nil {
 66→		var orgUUID uuid.UUID
 67→		orgUUID, err = uuid.Parse(currentOrg.ID)
 68→		if err != nil {
 69→			return nil, fmt.Errorf("invalid org UUID: %w", err)
 70→		}
 71→
 72→		// Apply RBAC visibility for api tokens (only for the current organization)
 73→		orgsProjectsMap := make(map[uuid.UUID][]uuid.UUID)
 74→		visibleProjects := s.visibleProjects(ctx)
 75→		if visibleProjects != nil {
 76→			orgsProjectsMap[orgUUID] = visibleProjects
 77→		}
 78→
 79→		referrer, nextCursor, err = s.referrerUC.GetFromRoot(ctx, req.GetDigest(), req.GetKind(), []uuid.UUID{orgUUID}, orgsProjectsMap, paginationOpts)
 80→	}
 81→	if err != nil {
 82→		return nil, handleUseCaseErr(err, s.log)
 83→	}
 84→
 85→	return &pb.ReferrerServiceDiscoverPrivateResponse{
 86→		Result:     bizReferrerToPb(referrer),
 87→		Pagination: bizCursorToPb(nextCursor),
 88→	}, nil
 89→}
