 96→
 97→	res, nextCursor, err := s.referrerUC.GetFromRootInPublicSharedIndex(ctx, req.GetDigest(), req.GetKind(), paginationOpts)
 98→	if err != nil {
 99→		return nil, handleUseCaseErr(err, s.log)
100→	}
101→
102→	return &pb.DiscoverPublicSharedResponse{
103→		Result:     bizReferrerToPb(res),
104→		Pagination: bizCursorToPb(nextCursor),
105→	}, nil
