120→func bizReferrerToPb(r *biz.StoredReferrer) *pb.ReferrerItem {
121→	item := &pb.ReferrerItem{
122→		Digest:       r.Digest,
123→		Downloadable: r.Downloadable,
124→		Public:       r.InPublicWorkflow,
125→		Kind:         r.Kind,
126→		CreatedAt:    timestamppb.New(*r.CreatedAt),
127→		Metadata:     r.Metadata,
128→		Annotations:  r.Annotations,
129→	}
130→
131→	for _, r := range r.References {
132→		item.References = append(item.References, bizReferrerToPb(r))
133→	}
134→
135→	return item
136→}
