 50→type storedReferrerMap map[string]uuid.UUID
 51→
 52→func (r *ReferrerRepo) Save(ctx context.Context, referrers []*biz.Referrer, workflowID uuid.UUID) (err error) {
 53→	// find the workflow
 54→	wf, err := r.workflowRepo.FindByID(ctx, workflowID)
 55→	if err != nil {
 56→		return fmt.Errorf("failed to find workflow: %w", err)
 57→	} else if wf == nil {
 58→		return biz.NewErrNotFound("workflow")
 59→	}
 60→
 61→	storedMap := make(storedReferrerMap)
 62→
 63→	for _, ref := range referrers {
 64→		// Check if it exists already, if not create it
 65→		storedID, err := r.data.DB.Referrer.Create().
 66→			SetDigest(ref.Digest).SetKind(ref.Kind).SetDownloadable(ref.Downloadable).
 67→			SetMetadata(ref.Metadata).SetAnnotations(ref.Annotations).
 68→			AddWorkflowIDs(workflowID).
 69→			OnConflictColumns(
 70→				referrer.FieldDigest, referrer.FieldKind,
 71→			).UpdateNewValues().ID(ctx)
 72→		if err != nil {
 73→			return fmt.Errorf("failed to create referrer: %w", err)
 74→		}
 75→
 76→		storedRef, err := r.data.DB.Referrer.Query().Select(referrer.FieldID).Where(referrer.ID(storedID)).First(ctx)
 77→		if err != nil {
 78→			return fmt.Errorf("failed to load referrer: %w", err)
 79→		} else if storedRef == nil {
 80→			return fmt.Errorf("failed to load referrer: %w", err)
 81→		}
 82→
 83→		// Store it in the map
 84→		storedMap[ref.MapID()] = storedRef.ID
 85→	}
 86→
 87→	// 2 - define the relationship between referrers
 88→	for _, parentRef := range referrers {
 89→		// This is the current item stored in DB
 90→		storedReferrer := storedMap[parentRef.MapID()]
 91→		// Iterate on the items it refer to (references)
 92→		var references []uuid.UUID
 93→		for _, ref := range parentRef.References {
 94→			// amd find it in the DB
 95→			storedReference, ok := storedMap[ref.MapID()]
 96→			if !ok {
 97→				return fmt.Errorf("referrer %v not found", ref)
 98→			}
 99→
100→			references = append(references, storedReference)
101→		}
102→
103→		if len(references) == 0 {
104→			continue
105→		}
106→
107→		// Create the relationship
108→		if err := r.data.DB.Referrer.UpdateOneID(storedReferrer).AddReferenceIDs(references...).Exec(ctx); err != nil {
109→			return fmt.Errorf("failed to create referrer relationship: %w", err)
110→		}
111→	}
112→
113→	return nil
114→}
