116→// Check if a given referrer by digest exist. The query can be scoped further down if needed by providing the kind or visibility status
117→func (r *ReferrerRepo) Exist(ctx context.Context, digest string, filters ...biz.GetFromRootFilter) (bool, error) {
118→	opts := &biz.GetFromRootFilters{}
119→	for _, f := range filters {
120→		f(opts)
121→	}
122→
123→	query := r.data.DB.Referrer.Query().Where(referrer.DigestEQ(digest))
124→	// We might be filtering by the rootKind, this will prevent ambiguity
125→	if opts.RootKind != nil {
126→		query = query.Where(referrer.Kind(*opts.RootKind))
127→	}
128→
129→	if opts.Public != nil {
130→		query = query.WithWorkflows(func(q *ent.WorkflowQuery) { q.Where(workflow.PublicEQ(*opts.Public)) })
131→	}
132→
133→	return query.Exist(ctx)
134→}
