137→	opts := &biz.GetFromRootFilters{}
138→	for _, f := range filters {
139→		f(opts)
140→	}
141→
142→	// Find the referrer from its digest + artifactType (optional)
143→	// if there is more than 1 item we return ReferrerAmbiguous error
144→	// filter by the allowed organizations and by the visibility of the attached workflows if needed
145→	predicateReferrer := []predicate.Referrer{
146→		referrer.Digest(digest),
147→	}
148→
149→	// We might be filtering by the rootKind, this will prevent ambiguity
150→	if opts.RootKind != nil {
151→		predicateReferrer = append(predicateReferrer, referrer.Kind(*opts.RootKind))
152→	}
153→
154→	// Prepare the workflow query predicate
155→	predicateWF := []predicate.Workflow{
156→		workflow.DeletedAtIsNil(), workflow.HasOrganizationWith(organization.IDIn(orgIDs...)),
157→	}
158→
159→	// optionally attaching its visibility
160→	if opts.Public != nil {
161→		predicateWF = append(predicateWF, workflow.Public(*opts.Public))
162→	}
163→
164→	// Attach the workflow predicate
165→	predicateReferrer = append(predicateReferrer, referrer.HasWorkflowsWith(predicateWF...))
166→
167→	refs, err := r.data.DB.Referrer.Query().Where(predicateReferrer...).WithWorkflows().All(ctx)
168→	if err != nil {
169→		return nil, "", fmt.Errorf("failed to query referrer: %w", err)
170→	}
171→
172→	// No items found
173→	if numrefs := len(refs); numrefs == 0 {
174→		return nil, "", nil
175→	} else if numrefs > 1 {
176→		// if there is more than 1 item with the same digest+artifactType we will fail
177→		var kinds []string
178→		for _, r := range refs {
179→			kinds = append(kinds, r.Kind)
180→		}
181→		return nil, "", biz.NewErrReferrerAmbiguous(digest, kinds)
182→	}
183→
184→	// Find the referrer recursively starting from the root
185→	res, nextCursor, err := r.doGet(ctx, refs[0], orgIDs, opts.ProjectIDs, opts.Public, p, 0)
186→	if err != nil && !biz.IsErrUnauthorized(err) {
187→		return nil, "", fmt.Errorf("failed to get referrer: %w", err)
188→	}
189→
190→	return res, nextCursor, nil
191→}
192→
193→// max number of recursive levels to traverse
194→// we just care about 1 level, i.e att -> commit, or commit -> attestation
195→// we also need to limit this because there might be cycles
196→const maxTraverseLevels = 1
197→
198→func (r *ReferrerRepo) doGet(ctx context.Context, root *ent.Referrer, allowedOrgs []uuid.UUID, visibleProjectsMap map[uuid.UUID][]uuid.UUID, public *bool, p *pagination.CursorOptions, level int) (*biz.StoredReferrer, string, error) {
199→	// Assemble the referrer to return
200→	res := &biz.StoredReferrer{
201→		ID:        root.ID,
202→		CreatedAt: toTimePtr(root.CreatedAt),
203→		Referrer: &biz.Referrer{
204→			Digest:       root.Digest,
205→			Kind:         root.Kind,
206→			Downloadable: root.Downloadable,
207→			Metadata:     root.Metadata,
208→			Annotations:  root.Annotations,
209→		},
210→	}
211→
212→	// add additional information related to the workflows
213→	hydrateWorkflowsInfo(root, res)
214→
215→	// check that, if RBAC is required, the user has visibility on the artifact in at least 1 org/project
216→	if visible := isReferrerVisible(res, allowedOrgs, visibleProjectsMap); !visible {
217→		return nil, "", biz.NewErrUnauthorizedStr("referrer not allowed")
218→	}
219→
220→	// Next: We'll find the references recursively up to a max of maxTraverseLevels levels
221→	if level >= maxTraverseLevels {
222→		return res, "", nil
223→	}
224→
225→	// Find the references and call recursively filtered out by the allowed organizations
226→	// and by the visibility if needed
227→	predicateReferrer := []predicate.Referrer{}
228→
229→	predicateWF := []predicate.Workflow{
230→		workflow.DeletedAtIsNil(), workflow.HasOrganizationWith(organization.IDIn(allowedOrgs...)),
231→	}
232→
233→	// optionally attaching its visibility
234→	if public != nil {
235→		predicateWF = append(predicateWF, workflow.Public(*public))
236→	}
237→
238→	// Attach the workflow predicate
239→	predicateReferrer = append(predicateReferrer, referrer.HasWorkflowsWith(predicateWF...))
240→
241→	// Sort references by creation date and ID in descending order for deterministic pagination
242→	q := root.QueryReferences().Where(predicateReferrer...).WithWorkflows().
243→		Order(referrer.ByCreatedAt(), ent.Desc()).
244→		Order(referrer.ByID(), ent.Desc())
245→
246→	// Apply pagination: fetch limit+1 to detect next page
247→	if p != nil {
248→		q = q.Limit(p.Limit + 1)
249→
250→		if p.Cursor != nil {
251→			q = q.Where(func(s *sql.Selector) {
252→				s.Where(sql.CompositeLT(
253→					[]string{s.C(referrer.FieldCreatedAt), s.C(referrer.FieldID)},
254→					p.Cursor.Timestamp, p.Cursor.ID,
255→				))
256→			})
257→		}
258→	}
259→
260→	refs, err := q.All(ctx)
261→	if err != nil {
262→		return nil, "", fmt.Errorf("failed to query references: %w", err)
263→	}
264→
265→	// Determine if there is a next page and encode the cursor
266→	var nextCursor string
267→	if p != nil && len(refs) > p.Limit {
268→		lastVisible := refs[p.Limit-1]
269→		nextCursor = pagination.EncodeCursor(lastVisible.CreatedAt, lastVisible.ID)
270→		refs = refs[:p.Limit]
271→	}
272→
273→	// Add the references to the result
274→	for _, reference := range refs {
275→		// Call recursively the function — pagination only applies to the first level
276→		ref, _, err := r.doGet(ctx, reference, allowedOrgs, visibleProjectsMap, public, nil, level+1)
277→		if err != nil && !biz.IsErrUnauthorized(err) {
278→			return nil, "", fmt.Errorf("failed to get referrer: %w", err)
279→		}
280→
281→		if ref != nil {
282→			res.References = append(res.References, ref)
283→		}
284→	}
285→
286→	return res, nextCursor, nil
287→}
288→
289→func isReferrerVisible(ref *biz.StoredReferrer, allowedOrgs []uuid.UUID, visibleProjectsMap map[uuid.UUID][]uuid.UUID) bool {
290→	if ref.InPublicWorkflow {
291→		return true
292→	}
293→
294→	for _, oid := range ref.OrgIDs {
295→		if !slices.Contains(allowedOrgs, oid) {
296→			// skip check in organizations where the user doesn't have access
297→			continue
298→		}
299→		if visibleProjects, ok := visibleProjectsMap[oid]; ok {
300→			// if entry is present, it means we need to apply RBAC
301→			// check if visible projects and referrer projects match
302→			// by checking if any project is visible by the user
303→			for _, pid := range ref.ProjectIDs {
304→				if slices.Contains(visibleProjects, pid) {
305→					return true
306→				}
307→			}
308→		} else {
309→			// if entry is not found in the map, it means that RBAC is not needed for this org, we have finished
310→			return true
311→		}
312→	}
313→
314→	return false
315→}
316→
317→// hydrate the referrer with the following information:
318→// - isPublic: if it has a public workflow associated
319→// - workflowIDs: the list of associated workflows
320→// - orgIDs: the list of associated organizations
321→func hydrateWorkflowsInfo(root *ent.Referrer, out *biz.StoredReferrer) {
322→	isPublic := false
323→	workflowIDs := make([]uuid.UUID, 0, len(root.Edges.Workflows))
324→	projectIDs := make(map[uuid.UUID]bool, 0)
325→	orgIDs := make([]uuid.UUID, 0)
326→	orgsMap := make(map[uuid.UUID]struct{}, 0)
327→	for _, wf := range root.Edges.Workflows {
328→		if wf.Public {
329→			isPublic = true
330→		}
331→		workflowIDs = append(workflowIDs, wf.ID)
332→		if _, ok := orgsMap[wf.OrganizationID]; !ok {
333→			orgIDs = append(orgIDs, wf.OrganizationID)
334→		}
335→		if _, ok := projectIDs[wf.ProjectID]; !ok {
336→			projectIDs[wf.ProjectID] = true
337→		}
338→		orgsMap[wf.OrganizationID] = struct{}{}
339→	}
340→
341→	out.ProjectIDs = maps.Keys(projectIDs)
342→	out.InPublicWorkflow = isPublic
343→	out.WorkflowIDs = workflowIDs
344→	out.OrgIDs = orgIDs
345→}
