110→// referrerPaginationOptsFromProto converts the proto pagination request to cursor options.
111→// It always returns non-nil options, defaulting to limit=20 when no pagination is provided.
112→func referrerPaginationOptsFromProto(p *pb.CursorPaginationRequest) (*pagination.CursorOptions, error) {
113→	limit := int(p.GetLimit())
114→	if limit == 0 {
115→		limit = defaultReferrerPageSize
116→	}
117→	return pagination.NewCursor(p.GetCursor(), limit)
118→}
