155→// ExtractAndPersist extracts the referrers (subject + materials) from the given attestation
156→// and store it as part of the referrers index table
157→func (s *ReferrerUseCase) ExtractAndPersist(ctx context.Context, att *dsse.Envelope, digest cr_v1.Hash, workflowID string) error {
158→	workflowUUID, err := uuid.Parse(workflowID)
159→	if err != nil {
160→		return NewErrInvalidUUID(err)
161→	}
162→
163→	// Check that the workflow belongs to the organization
164→	if wf, err := s.workflowRepo.FindByID(ctx, workflowUUID); err != nil {
165→		return fmt.Errorf("finding workflow: %w", err)
166→	} else if wf == nil {
167→		return NewErrNotFound("workflow")
168→	}
169→
170→	referrers, err := extractReferrers(att, digest, s.repo)
171→	if err != nil {
172→		return fmt.Errorf("extracting referrers: %w", err)
173→	}
174→
175→	if err := s.repo.Save(ctx, referrers, workflowUUID); err != nil {
176→		return fmt.Errorf("saving referrers: %w", err)
177→	}
178→
179→	return nil
180→}
