182→// GetFromRootUser returns the referrer identified by the provided content digest, including its first-level references.
183→// For example if sha:deadbeef represents an attestation, the result will contain the attestation + materials associated to it.
184→// It only returns referrers that belong to organizations the user is member of.
185→func (s *ReferrerUseCase) GetFromRootUser(ctx context.Context, digest, rootKind, userID string, p *pagination.CursorOptions) (*StoredReferrer, string, error) {
186→	userUUID, err := uuid.Parse(userID)
187→	if err != nil {
188→		return nil, "", NewErrInvalidUUID(err)
189→	}
190→
191→	userOrgs, projectIDs, err := s.membershipUseCase.GetOrgsAndRBACInfoForUser(ctx, userUUID)
192→	if err != nil {
193→		return nil, "", err
194→	}
195→
196→	// We pass the list of organizationsIDs from where to look for the referrer
197→	// For now we just pass the list of organizations the user is member of
198→	// in the future we will expand this to publicly available orgs and so on.
199→	return s.GetFromRoot(ctx, digest, rootKind, userOrgs, projectIDs, p)
200→}
