202→func (s *ReferrerUseCase) GetFromRoot(ctx context.Context, digest, rootKind string, orgIDs []uuid.UUID, projectIDs map[OrgID][]ProjectID, p *pagination.CursorOptions) (*StoredReferrer, string, error) {
203→	filters := make([]GetFromRootFilter, 0)
204→	if rootKind != "" {
205→		filters = append(filters, WithKind(rootKind))
206→	}
207→	if projectIDs != nil {
208→		filters = append(filters, WithVisibleProjectIDs(projectIDs))
209→	}
210→
211→	ref, nextCursor, err := s.repo.GetFromRoot(ctx, digest, orgIDs, p, filters...)
212→	if err != nil {
213→		if errors.As(err, &ErrAmbiguousReferrer{}) {
214→			return nil, "", NewErrValidation(fmt.Errorf("please provide the referrer kind: %w", err))
215→		}
216→
217→		return nil, "", fmt.Errorf("getting referrer from root: %w", err)
218→	} else if ref == nil {
219→		return nil, "", NewErrNotFound(fmt.Sprintf("artifact or piece of evidence with digest %s", digest))
220→	}
221→
222→	return ref, nextCursor, nil
223→}
