276→// ExtractReferrers extracts the referrers from the given attestation
277→// this means
278→// 1 - write an entry for the attestation itself
279→// 2 - then to all the materials contained in the predicate
280→// 3 - and the subjects (some of them)
281→// 4 - creating link between the attestation and the materials/subjects as needed
282→// see tests for examples
283→func extractReferrers(att *dsse.Envelope, digest cr_v1.Hash, repo ReferrerRepo) ([]*Referrer, error) {
284→	referrersMap := make(map[string]*Referrer)
285→	// 1 - Attestation referrer
286→	// Add the attestation itself as a referrer to the map without references yet
287→	attestationHash := digest.String()
288→	attestationReferrer := &Referrer{
289→		Digest:       attestationHash,
290→		Kind:         referrerAttestationType,
291→		Downloadable: true,
292→	}
293→
294→	referrersMap[newRef(attestationHash, referrerAttestationType)] = attestationReferrer
295→
296→	// 2 - Predicate that's referenced from the attestation
297→	predicate, err := chainloop.ExtractPredicate(att)
298→	if err != nil {
299→		return nil, fmt.Errorf("extracting predicate: %w", err)
300→	}
301→
302→	// We currently only support adding additional information about the attestation kind
303→	// We add both annotations and workflow metadata
304→	attestationReferrer.Annotations = predicate.GetAnnotations()
305→	hasViolations := predicate.GetPolicyEvaluationStatus().HasViolations
306→	hasGatedViolations := predicate.GetPolicyEvaluationStatus().HasGatedViolations
307→	attestationReferrer.Metadata = map[string]string{
308→		// workflow name, team and project
309→		"name":                     predicate.GetMetadata().Name,
310→		"team":                     predicate.GetMetadata().Team,
311→		"project":                  predicate.GetMetadata().Project,
312→		"hasPolicyViolations":      fmt.Sprintf("%t", hasViolations),
313→		"hasGatedPolicyViolations": fmt.Sprintf("%t", hasGatedViolations),
314→		"projectVersion":           predicate.GetMetadata().ProjectVersion,
315→		"projectVersionPrerelease": fmt.Sprintf("%t", predicate.GetMetadata().ProjectVersionPrerelease),
316→		"organization":             predicate.GetMetadata().Organization,
317→		"contractName":             predicate.GetMetadata().ContractName,
318→		"contractVersion":          predicate.GetMetadata().ContractVersion,
319→	}
320→
321→	// Create new referrers for each material
322→	// and link them to the attestation
323→	for _, material := range predicate.GetMaterials() {
324→		// Skip materials that don't have a digest
325→		if material.Hash == nil {
326→			continue
327→		}
328→
329→		// If we are inserting an attestation as a dependent, we want to make sure it already exists
330→		// stored in the system. This is so we can ensure that the attestations nodes are created through
331→		// an attestation process, not as a referenced provided by the user
332→		if material.Type == referrerAttestationType {
333→			if exists, err := repo.Exist(context.Background(), material.Hash.String(), WithKind(referrerAttestationType)); err != nil {
334→				return nil, fmt.Errorf("checking if attestation exists: %w", err)
335→			} else if !exists {
336→				return nil, fmt.Errorf("attestation material does not exist %q", material.Hash.String())
337→			}
338→		}
339→
340→		// Create its referrer entry if it doesn't exist yet
341→		// the reason it might exist is because you might be attaching the same material twice
342→		// i.e the same SBOM twice, in that case we don't want to create a new referrer
343→		materialRef := newRef(material.Hash.String(), material.Type)
344→		if _, ok := referrersMap[materialRef]; ok {
345→			continue
346→		}
347→
348→		referrersMap[materialRef] = &Referrer{
349→			Digest:       material.Hash.String(),
350→			Kind:         material.Type,
351→			Downloadable: material.UploadedToCAS,
352→		}
353→
354→		materialReferrer := referrersMap[materialRef]
355→
356→		// We create a bidirectional link between the attestation and the material
357→		// material -> attestation (1-1)
358→		materialReferrer.References = []*Referrer{{Digest: attestationReferrer.Digest, Kind: attestationReferrer.Kind}}
359→		// attestation -> material (1-N)
360→		attestationReferrer.References = append(attestationReferrer.References, &Referrer{
361→			Digest: materialReferrer.Digest, Kind: materialReferrer.Kind,
362→		})
363→	}
364→
365→	// 3 - Subject that points to the attestation
366→	statement, err := chainloop.ExtractStatement(att)
367→	if err != nil {
368→		return nil, fmt.Errorf("extracting predicate: %w", err)
369→	}
370→
371→	// Materials can also be subjects, but there are cases that we will have a subject that is not a material
372→	// For example, a git head commit, that's why we need to also add the subjects as referrers (if needed)
373→	for _, subject := range statement.Subject {
374→		subjectReferrer, err := intotoSubjectToReferrer(subject)
375→		if err != nil {
376→			return nil, fmt.Errorf("transforming subject to referrer: %w", err)
377→		}
378→
379→		if subjectReferrer == nil {
380→			continue
381→		}
382→
383→		subjectRef := newRef(subjectReferrer.Digest, subjectReferrer.Kind)
384→
385→		// check if we already have a referrer for this digest and skip if it's the case
386→		if _, ok := referrersMap[subjectRef]; ok {
387→			continue
388→		}
389→
390→		// We are now in the case where a subject is not a material, i.e a git head commit, we need to add it to the referrers
391→		// with a bidirectional link to the attestation like we did for the materials
392→		referrersMap[subjectRef] = subjectReferrer
393→		// add it to the list of of attestation-referenced digests
394→		attestationReferrer.References = append(attestationReferrer.References,
395→			&Referrer{
396→				Digest: subjectReferrer.Digest, Kind: subjectReferrer.Kind,
397→			})
398→
399→		// Update referrer to point to the attestation
400→		referrersMap[subjectRef].References = []*Referrer{{Digest: attestationReferrer.Digest, Kind: attestationReferrer.Kind}}
401→	}
402→
403→	// Return a sorted list of referrers
404→	mapKeys := make([]string, 0, len(referrersMap))
405→	for k := range referrersMap {
406→		mapKeys = append(mapKeys, k)
407→	}
408→	sort.Strings(mapKeys)
409→
410→	referrers := make([]*Referrer, 0, len(referrersMap))
411→	for _, k := range mapKeys {
412→		referrers = append(referrers, referrersMap[k])
413→	}
414→
415→	return referrers, nil
416→}
417→
418→// transforms the in-toto subject to a referrer by deterministically picking
419→// the subject types we care about (and return nil otherwise), for now we just care about the subjects
420→// - git.Head and
421→// - material types
422→func intotoSubjectToReferrer(r *v1.ResourceDescriptor) (*Referrer, error) {
423→	var digestStr string
424→	for alg, val := range r.Digest {
425→		digestStr = fmt.Sprintf("%s:%s", alg, val)
426→		break
427→	}
428→
429→	// it's a.git head type
430→	if r.Name == chainloop.SubjectGitHead {
431→		if digestStr == "" {
432→			return nil, fmt.Errorf("no digest found for subject %s", r.Name)
433→		}
434→
435→		return &Referrer{
436→			Digest: digestStr,
437→			Kind:   referrerGitHeadType,
438→		}, nil
439→	}
440→
441→	// Iterate on material types
442→	var materialType string
443→	var uploadedToCAS bool
444→	// it's a material type
445→	for k, v := range r.Annotations.AsMap() {
446→		// It's a material type
447→		if k == v2.AnnotationMaterialType {
448→			materialType = v.(string)
449→		} else if k == v2.AnnotationMaterialCAS {
450→			uploadedToCAS = v.(bool)
451→		}
452→	}
453→
454→	// it's not a material type
455→	if materialType == "" {
456→		return nil, nil
457→	}
458→
459→	if digestStr == "" {
460→		return nil, fmt.Errorf("no digest found for subject %s", r.Name)
461→	}
462→
463→	return &Referrer{
464→		Digest:       digestStr,
465→		Kind:         materialType,
466→		Downloadable: uploadedToCAS,
467→	}, nil
468→}
